/* PIGMENT — Tier 1 artist overlay (25 artists).
   Per ARTWORK_SCHEMA tiering + STYLE_GUIDE §4.2–4.3:
   why    — 40–60 words: the claim, the visible evidence, the lineage
   lookFor — 3–5 traits, each a thing the eye can find
   goNext  — 3–4 onward doors: {t: artist|movement|technique|work, id, why}
   coords  — hand-scored Tier 1 taste vector (TASTE_MATH scale −100…+100) */
window.TIER1 = {

"leonardo-da-vinci": {
  why: "Leonardo made painting a form of research: light studied like physics, faces like anatomy, landscapes like geology. Sfumato — modelling without lines — gave images an inner weather no one had achieved before. Every painter who ever blurred an edge to suggest a soul is quoting him.",
  lookFor: ["Smoky, lineless transitions between light and shade","Faces caught between two expressions","Blue geological fantasy landscapes behind sitters","Hands that speak as much as faces"],
  goNext: [
    { t:"artist", id:"raphael", why:"his grace, systematized" },
    { t:"artist", id:"michelangelo", why:"the rival, and the opposite answer" },
    { t:"technique", id:"sfumato", why:"the smoke itself" },
    { t:"movement", id:"high-renaissance", why:"the summit he defined" }],
  coords: { F:-85, D:-15, E:5, C:15, M:-15 },
  arc: [
    { y:"1452–66", t:"The notary's natural son",
      text:"Born out of wedlock in Vinci, which closes the respectable professions — a stroke of luck for painting. Apprenticed to Verrocchio in Florence, he paints an angel so fine that, the story goes, his master gave up painting for good. The story is too neat; Vasari couldn't resist it either." },
    { y:"1472–81", t:"Florence: brilliant, unfinished",
      text:"A guild master at twenty, he paints an Annunciation with botanically real flowers and a portrait of Ginevra de' Benci with the first psychological weather in Florentine art. He also starts abandoning things — the Adoration of the Magi is left half-ghost when Milan calls. The pattern of his life is set.",
      works:["annunciation-leonardo","ginevra-de-benci"] },
    { y:"1482–99", t:"Milan: the engineer",
      text:"His job letter to Duke Ludovico Sforza lists war machines for nine paragraphs and mentions painting almost as a footnote. Seventeen years in Milan produce canal designs, pageants, a colossal horse never cast — and, almost incidentally, the Virgin of the Rocks and the duke's mistress with an ermine.",
      works:["virgin-of-the-rocks","lady-with-an-ermine","la-belle-ferronniere"] },
    { y:"1495–98", t:"The Supper",
      text:"On a refectory wall he stages the instant after 'one of you will betray me' — and, hating fresco's speed, invents his own slow technique to do it. The chemistry fails within decades; the composition conquers the world anyway. Monks later cut a door through Christ's feet.",
      works:["the-last-supper"] },
    { y:"c. 1490–1519", t:"The notebooks",
      text:"Seven thousand surviving pages, mirror-written: dissections by candlelight, water braiding around obstacles, flying machines, the moon's light explained. Painting, he argues there, is the supreme science — the eye's mathematics. He published none of it; the notebooks outthink his century in private.",
      works:["vitruvian-man"] },
    { y:"1500–06", t:"Florence: the duel and the smile",
      text:"Back in Florence he duels Michelangelo across a council-hall wall — both battle murals end unfinished, art history's great near-miss — and begins a portrait of a silk merchant's wife, Lisa del Giocondo. He never delivers it. He carries her, perfecting the smile, for the rest of his life.",
      works:["mona-lisa"] },
    { y:"1508–16", t:"Restless decades",
      text:"Milan again, then Rome, where younger men — Michelangelo on the ceiling, Raphael in the stanze — get the walls, and Leonardo gets anatomy disputes and unfinished commissions. His last painting is a Baptist smiling out of darkness, pointing up at something only he seems to see.",
      works:["saint-john-the-baptist-leonardo"] },
    { y:"1516–19", t:"The king's guest",
      text:"Francis I installs him in a manor by the Loire with a pension and no duties beyond conversation — 'no man knew as much,' the king said later. He arrives with three paintings in his baggage, Mona Lisa among them, designs court festivals, and dies in May 1519, leaving the notebooks to his devoted Melzi." },
    { y:"1519–", t:"The relic",
      text:"Perhaps fifteen paintings survive — the smallest output of any artist of his rank, guarded now like relics behind glass. The notebooks scattered across Europe's libraries; one, the Codex Leicester, became the most expensive book ever sold. The unfinished life turned out to be the point: he left the questions open on purpose." }
  ] },

"michelangelo": {
  why: "Michelangelo put the human body in charge of meaning: theology told through torsos, salvation through musculature. The Sistine ceiling made paint monumental; the Last Judgment made it terrifying. Mannerism, the Baroque, and every heroic nude since are footnotes to his anatomy.",
  lookFor: ["Twisting, spiral poses under strain","Muscle on everyone — angels and women included","Sculptural figures against minimal settings","Bodies drawn grander than their architecture"],
  goNext: [
    { t:"artist", id:"tintoretto", why:"his drawing, Venice's color" },
    { t:"artist", id:"raphael", why:"the courteous rival next door" },
    { t:"movement", id:"mannerism", why:"what his style became unleashed" },
    { t:"technique", id:"fresco", why:"the arena of the ceiling" }],
  coords: { F:-80, D:60, E:-10, C:0, M:90 },
  arc: [
    { y:"1475–92", t:"The Medici garden",
      text:"Born at Caprese, nursed by a stonecutter's wife — 'with my nurse's milk I sucked in the chisels,' he liked to say. Apprenticed to the fresco master Ghirlandaio at thirteen, poached for Lorenzo de' Medici's sculpture garden at fifteen, and given a broken nose for his arrogance by a fellow student. Around this time: a painted Saint Anthony mobbed by demons, after a German print.",
      works:["torment-of-saint-anthony"] },
    { y:"1498–99", t:"The Pietà",
      text:"At twenty-three he carves a dead Christ in his mother's lap so finished it seems poured, not cut. Overhearing pilgrims credit a Lombard sculptor, he slips in at night and chisels his name across Mary's sash — the only work he ever signed, a vanity he reportedly regretted at once.",
      works:["pieta"] },
    { y:"1501–04", t:"The giant",
      text:"A colossal marble block, botched and abandoned for forty years, is given to the twenty-six-year-old. Three years later Florence needs four days and forty men to walk David to the town hall while partisans throw stones at it. The republic has its icon; sculpture has its measuring stick.",
      works:["david"] },
    { y:"1504–08", t:"The tondo and the trap",
      text:"His only finished panel painting, the Doni Tondo, twists the Holy Family into sculpture's poses in acid colors. Then Pope Julius II summons him for a tomb with forty figures — the commission shrinks for forty years, and Michelangelo will call it the tragedy of his life.",
      works:["doni-tondo"] },
    { y:"1508–12", t:"The ceiling",
      text:"He suspects the ceiling commission is a rival's scheme to watch him fail at fresco. He fires his assistants within months and paints five thousand square feet essentially alone — standing, head back, four years. His sonnet complains the brush drips into his face and ends: I am no painter.",
      works:["sistine-chapel-ceiling","the-creation-of-adam"] },
    { y:"1527–34", t:"The fortifier",
      text:"When Florence expels the Medici and the Medici pope besieges it, the republic's fortifications are designed by its most famous artist. After the fall he hides in a crypt under a Medici chapel, sketching on the walls by lamplight — the room was found, drawings intact, in 1975. Pardoned, he leaves Florence in 1534 and never returns.",
      works:["entombment-michelangelo"] },
    { y:"1536–41", t:"The Judgment",
      text:"Twenty-five years after the ceiling he returns to paint the altar wall: three hundred bodies spiraling up to heaven and down to hell around a beardless judging Christ. When the pope's master of ceremonies calls it bathhouse art, Michelangelo paints him into hell with donkey ears — and the pope declines to intervene in hell's jurisdiction.",
      works:["the-last-judgment"] },
    { y:"1546–64", t:"The architect",
      text:"Old age brings St Peter's: he takes over the dome 'for the love of God, without fee,' redesigning the crossing that defines Rome's skyline. At home he writes sonnets to Vittoria Colonna and Tommaso de' Cavalieri, and attacks a late Pietà with a hammer when the marble disappoints him." },
    { y:"1564", t:"The last chisel",
      text:"Witnesses say he was carving the Rondanini Pietà — Christ and mother dissolving into each other, almost Gothic again — six days before he died at eighty-eight. Rome wanted the body; his nephew smuggled it to Florence disguised as merchandise, and the city buried him like a prince." }
  ] },

"hieronymus-bosch": {
  why: "Five centuries before Surrealism had a manifesto, Bosch painted moral philosophy as hallucination — tree-bodied demons, egg-shaped hells, humanity swarming toward its appetites. Nobody knows quite what he meant, which is the engine of his immortality: every age reads its own nightmare into him.",
  lookFor: ["Hybrid creatures assembled from the wrong parts","Dozens of tiny scenes teeming inside one panel","Glassy spheres, eggs and hollow shells","Hell rendered busier than heaven"],
  goNext: [
    { t:"artist", id:"pieter-bruegel", why:"the heir who grounded the visions" },
    { t:"artist", id:"salvador-dali", why:"the 20th-century disciple" },
    { t:"work", id:"the-garden-of-earthly-delights", why:"the whole cosmology in three panels" },
    { t:"movement", id:"northern-renaissance", why:"his strange home" }],
  coords: { F:-70, D:65, E:70, C:45, M:30 },
  arc: [
    { y:"c. 1450–74", t:"Born into the trade",
      text:"Jheronimus van Aken grows up over a painter's workshop in 's-Hertogenbosch — grandfather, father, uncles, brothers, all painters. When he is about thirteen a fire guts the town; whether or not the memory seeded his burning skylines, fires never stop appearing in his hells." },
    { y:"c. 1480", t:"Marrying up",
      text:"He weds Aleid van de Meervenne, a merchant's daughter with money and a house on the market square. Freed from hackwork, he starts signing with the town's name instead of his family's: Bosch. The brand outlives the man by five centuries." },
    { y:"1486–87", t:"Brother of Our Lady",
      text:"He joins the Brotherhood of Our Lady — the town's elite confraternity, some fifty 'sworn brothers' among thousands of ordinary members — designing for their chapel and attending their swan banquets. It is the respectable center of his world: the man who painted hell was a pillar of the parish." },
    { y:"c. 1490–1500", t:"Fools and sins",
      text:"Moralities with a miniaturist's wit: a boatload of revelers drifting nowhere, Death arriving while a miser reaches for his gold with one hand and salvation with neither, the deadly sins arranged as the iris of God's eye with a warning — beware, beware, God sees.",
      works:["ship-of-fools","death-and-the-miser","seven-deadly-sins","stone-operation"] },
    { y:"c. 1495–1505", t:"The Garden",
      text:"His masterwork was probably never a church altarpiece: the triptych of Eden, a false paradise of strawberries, glass and acrobatic nudes, and a musical hell where instruments become instruments of torture, painted — scholars think — for a noble palace, as the most spectacular conversation piece in Europe.",
      works:["the-garden-of-earthly-delights"] },
    { y:"c. 1500–10", t:"Anthony besieged",
      text:"The Lisbon triptych sends Saint Anthony through a world where demons run on gadgetry — fish that fly, jugs that walk, a burning village for backlight. The hermit kneels at the center, steady amid the traffic. It was copied and forged in his own lifetime more than almost anything in Europe.",
      works:["temptation-of-saint-anthony"] },
    { y:"c. 1512–15", t:"The haywain",
      text:"Late in life he paints the world as a hay wagon rolling toward hell, every class grabbing its fistful as it passes. The proverb was common property; the panorama — greed as a landscape with weather — was his alone.",
      works:["the-haywain-triptych"] },
    { y:"1516", t:"Requiem for a brother",
      text:"He dies in the summer of 1516 — plague was in town — and receives a solemn funeral mass in the cathedral he'd worked beside all his life. No letters, no diary, no birth record survive: the most inexplicable imagination in European art comes down to us as forty dry documents and a signature." },
    { y:"1517–", t:"Boschmania",
      text:"Within decades Philip II of Spain is hoarding him — which is why the Prado owns the Garden and the Haywain — while Antwerp workshops mass-produce imitations and the young Bruegel launches as 'the new Bosch.' Four centuries later the Surrealists claim him as a founding father. His hometown owns none of his paintings." }
  ] },

"jan-van-eyck": {
  why: "Van Eyck perfected oil glazing so completely that legend credited him with inventing paint itself. Light travels into his panels and comes back changed — brocade you can rustle, mirrors holding whole rooms. Northern painting's entire tradition of total observation starts at his easel.",
  lookFor: ["Mirrors and reflections hiding extra rooms","Jewel-light built from transparent glazes","Inscriptions painted into the scene","Detail that survives any magnification"],
  goNext: [
    { t:"artist", id:"rogier-van-der-weyden", why:"observation, taught to weep" },
    { t:"work", id:"the-arnolfini-portrait", why:"the mirror trick at full power" },
    { t:"technique", id:"glazing", why:"the light machine itself" },
    { t:"movement", id:"early-netherlandish", why:"the school he anchors" }],
  coords: { F:-92, D:-35, E:-15, C:-10, M:-60 },
  arc: [
    { y:"c. 1390–1425", t:"Out of the Meuse valley",
      text:"His beginnings are guesswork — probably Maaseik, probably trained as a manuscript illuminator, which would explain the jeweler's patience. By 1425 he is court painter and 'varlet de chambre' to Philip the Good of Burgundy, the richest patron in Northern Europe, at a salary meant to keep him free of guild hackwork." },
    { y:"1426–29", t:"Secret missions",
      text:"The ducal accounts pay him for 'certain distant and secret journeys' — diplomacy still unexplained — and, in 1428, a trip to Lisbon to paint Princess Isabella of Portugal so Philip could inspect his bride before proposing. Two portraits went back by land and sea; both are lost. The marriage happened." },
    { y:"1432", t:"The altarpiece",
      text:"Ghent unveils the twelve-panel polyptych begun by his brother Hubert, who died in 1426, and finished by Jan: the Mystic Lamb bleeding calmly into a chalice while all creation gathers, painted in oil glazes that hold dew, hair and light inside gems. Painting's ceiling moves, permanently.",
      works:["ghent-altarpiece"] },
    { y:"1433", t:"'As I can'",
      text:"A small man in a red turban fixes us with the first direct gaze in panel portraiture — very possibly Jan himself. On the frame, painted as if carved, his lifelong motto puns on his name: Als Ich Can — as I can, as Eyck can. Modest and boastful in three words.",
      works:["man-in-a-red-turban"] },
    { y:"1434", t:"The Arnolfini contract",
      text:"A Lucca merchant and his wife stand in a Bruges bedroom among oranges, a brass chandelier and a convex mirror that reflects two visitors — above it, graffiti in legal script: 'Johannes de eyck fuit hic.' Jan van Eyck was here. Six centuries of argument about what, exactly, we are witnessing.",
      works:["the-arnolfini-portrait"] },
    { y:"c. 1434–36", t:"Painting for the chancellor",
      text:"For Burgundy's iron chancellor Rolin he paints the Virgin visiting a man at prayer — same scale, same room, a river empire unfolding behind them arch by arch. The donor no longer kneels in the margin; the patron has bought his way into the picture's very air.",
      works:["madonna-of-chancellor-rolin","annunciation-van-eyck"] },
    { y:"c. 1438–40", t:"Cathedrals in a hand's span",
      text:"Madonna in the Church puts a sixty-foot Virgin inside a Gothic nave on a panel a foot tall, sunlight pooling on the floor in two impossible, perfect patches. The glazes are stacked until light seems to pass through the paint rather than bounce off it.",
      works:["madonna-in-the-church"] },
    { y:"1439–41", t:"The debt repaid",
      text:"His last dated portrait is of Margaret, his wife, at thirty-three, painted 'as my husband can' — the motto turned domestic. He dies in Bruges in June 1441; the duke, who once said he could find no painter his equal, keeps paying the widow and funds a daughter's convent place.",
      works:["margaret-van-eyck"] },
    { y:"1441–", t:"The inventor who wasn't",
      text:"Vasari crowned him 'inventor of oil painting' — wrong, but close enough to stick: he perfected what he didn't invent, and nobody has out-painted the perfection. The Ghent Altarpiece went on to become the most stolen artwork in history; the Arnolfini mirror became painting's favorite riddle." }
  ] },

"caravaggio": {
  why: "Caravaggio detonated European painting in one decade: street kids as angels, pilgrims with dirty feet, miracles staged in cellar darkness under a single brutal light. Every noir shadow since — Rembrandt's, Ribera's, cinema's — runs on his electricity. He painted saints the way police light suspects.",
  lookFor: ["One raking light source, no visible origin","Models with lived-in faces and unwashed feet","Backgrounds swallowed in black","Action frozen at its most irreversible instant"],
  goNext: [
    { t:"artist", id:"artemisia-gentileschi", why:"his darkness, her fury" },
    { t:"artist", id:"georges-de-la-tour", why:"tenebrism gone silent" },
    { t:"technique", id:"tenebrism", why:"the lighting rig he invented" },
    { t:"work", id:"the-calling-of-saint-matthew", why:"the raid that started it" }],
  coords: { F:-85, D:90, E:20, C:-15, M:35 },
  arc: [
    { y:"1577", t:"Plague orphan",
      text:"Michelangelo Merisi is six when plague sweeps Lombardy and takes his father and grandfather on the same day. Apprenticed at thirteen in Milan, he absorbs the Lombard creed — paint what stands in front of you. Around 1592 he bolts for Rome, reportedly one step ahead of trouble over a wounded police officer." },
    { y:"1593–96", t:"Fruit boys on the make",
      text:"Penniless in Rome, he paints street boys, overripe fruit and rigged card games for the open market — con men observed as coolly as still lifes. Cardinal Del Monte buys The Cardsharps, gives the painter rooms in his palace, and starts supplying clients. The apprenticeship is over.",
      works:["boy-with-a-basket-of-fruit","the-cardsharps","bacchus-caravaggio"] },
    { y:"1599–1600", t:"Overnight, in a chapel",
      text:"His first public commission, for the Contarelli Chapel: Saint Matthew called from a tax table by a shaft of light that behaves like an arrest warrant. Rome has never seen sacred history staged in a tavern. Every painter in the city comes to look; half of them start over.",
      works:["the-calling-of-saint-matthew"] },
    { y:"1601–06", t:"Fame with a police file",
      text:"The most in-demand painter in Rome is also its most arrested — libel, illegal weapons, a waiter assaulted with a plate of artichokes. The pictures keep outrunning the scandals until Death of the Virgin, its Madonna reportedly modeled on a drowned courtesan, is refused by the monks who ordered it.",
      works:["judith-beheading-holofernes","the-entombment-of-christ","death-of-the-virgin"] },
    { y:"1606", t:"The murder",
      text:"A quarrel over a wagered tennis match — or a woman, or both — ends with Ranuccio Tomassoni bleeding to death on a Roman court and a capital sentence on Caravaggio's head: anyone may kill him on sight. He flees south to Naples, where nobody asks questions and everybody wants a Caravaggio." },
    { y:"1607", t:"Mercy, painted by a killer",
      text:"For a Naples charity he crams all seven works of mercy into one nocturnal street corner — corpse-bearers, a prisoner nursed through the bars, angels tangled in the dark overhead. The fugitive with blood on his hands paints compassion as street life, caught by torchlight.",
      works:["the-seven-works-of-mercy"] },
    { y:"1608", t:"Malta: knighted, then caged",
      text:"The Knights of St John make him a brother — the murderer reborn as Fra Michelangelo — and he pays with the largest canvas of his life, signed in the Baptist's blood. Within months he wounds a senior knight, is jailed in the rock, escapes by rope, and is expelled 'as a foul and rotten limb.'",
      works:["the-beheading-of-saint-john"] },
    { y:"1609–10", t:"The hunted man's plea",
      text:"Slashed across the face outside a Naples tavern, he paints his own severed head in David's fist and aims it at Rome, where Cardinal Scipione Borghese has the power to trade a pardon. The last pictures go darker still — bare brown grounds, faces surfacing out of nothing.",
      works:["david-with-the-head-of-goliath"] },
    { y:"1610", t:"The beach at Porto Ercole",
      text:"He sails north with paintings for the ransom, is mistakenly arrested at a coastal garrison, and watches the boat leave with them aboard. Days later, at thirty-eight, he is dead of fever on the beach — reportedly just before word of the pardon arrived. Painters have argued with his light ever since." }
  ] },

"artemisia-gentileschi": {
  why: "Artemisia took Caravaggio's darkness and gave it muscle, leverage and a point of view no man in the room possessed. Her Judiths don't flinch from the beheading — they brace into it. The first woman admitted to Florence's academy, she negotiated her fees like the master she was.",
  lookFor: ["Women who act rather than pose","Rolled sleeves and straining forearms","Blood with honest physics","Candlelit stages, three figures deep"],
  goNext: [
    { t:"artist", id:"caravaggio", why:"the source of the darkness" },
    { t:"artist", id:"lavinia-fontana", why:"the woman who opened the door first" },
    { t:"work", id:"judith-slaying-holofernes", why:"the manifesto" },
    { t:"movement", id:"baroque", why:"her arena" }],
  coords: { F:-88, D:88, E:15, C:-10, M:30 },
  arc: [
    { y:"1593–1610", t:"Orazio's daughter",
      text:"Her mother dies when she is twelve; she grows up grinding pigments in her father Orazio's Roman workshop, learning Caravaggio's new dark realism at the source. At seventeen she signs her first masterpiece: Susanna harassed by the elders — the old story, painted for once from the woman's side of the wall.",
      works:["susanna-and-the-elders"] },
    { y:"1611–12", t:"The trial",
      text:"Agostino Tassi, the painter hired to teach her perspective, rapes her. At the trial her father brings, it is Artemisia who is tortured with thumbscrews to test her word — 'è vero, è vero,' she repeats while the cords bite. Tassi is convicted; the sentence is never enforced. She is nineteen." },
    { y:"1612–13", t:"Judith answers",
      text:"Married off within weeks of the verdict and moved to Florence, she paints Judith beheading Holofernes with a butcher's matter-of-fact grip — two strong women doing hard work, blood soaking the sheets. Viewers have read biography into it for four centuries; the painting doesn't need the help.",
      works:["judith-beheading-holofernes-naples"] },
    { y:"1616–20", t:"Florence's first woman",
      text:"The Accademia del Disegno admits her — the first woman ever. She befriends Galileo, takes commissions from Michelangelo's grand-nephew, learns to read and write as an adult, and repaints her Judith bigger, darker and bloodier: the Uffizi version, with arterial spray Galileo's ballistics may have informed.",
      works:["judith-slaying-holofernes","self-portrait-as-saint-catherine"] },
    { y:"1620s", t:"Rome, Venice, candlelight",
      text:"Separated from her husband, she runs her own household and studio — almost unheard of for a woman — and paints heroines cornered by history: Lucretia at the knife's edge, and the Detroit Judith frozen by a sound in the dark, one hand shielding the candle.",
      works:["lucretia-getty","judith-and-her-maidservant-detroit"] },
    { y:"1630", t:"Naples, the business",
      text:"She settles in Naples, Spain's teeming southern capital, running a workshop, winning altarpiece commissions no woman had held, and haggling in letters that still sting: 'You will find the spirit of Caesar in this soul of a woman.'",
      works:["esther-before-ahasuerus"] },
    { y:"1638–40", t:"London: painting painting",
      text:"She joins her dying father at the court of Charles I and paints her boldest claim: herself as the Allegory of Painting — the emblem-book figure every male painter could only depict, and only she could be.",
      works:["self-portrait-as-the-allegory-of-painting"] },
    { y:"1640s–56", t:"The long professional",
      text:"Back in Naples she works another decade and a half, revisiting Susanna in calmer registers and running the studio through wars and plague. She dies around 1656, probably in the epidemic; contemporary satirists mock her marriages and miss her entirely." },
    { y:"1916–", t:"Recovered",
      text:"An essay by Roberto Longhi restarts her reputation; his wife Anna Banti's novel 'Artemisia' makes her a heroine; scholarship does the rest. Once a footnote to her father, she is now the most famous of all the Caravaggisti — including, some days, Caravaggio." }
  ] },

"rembrandt": {
  why: "Rembrandt traded the Baroque's theatre for inner weather: light that seems to come from inside people. Eighty self-portraits form painting's greatest autobiography; his late crusted surfaces, called unfinished then, look like the invention of modern paint-handling now. Nobody has made gloom feel warmer.",
  lookFor: ["Golden light with no clear source","Impasto thick enough to cast real shadows","Eyes that seem mid-thought","Etching lines scratched like handwriting"],
  goNext: [
    { t:"artist", id:"johannes-vermeer", why:"the other Dutch answer: silence" },
    { t:"artist", id:"kathe-kollwitz", why:"his etching needle, centuries on" },
    { t:"technique", id:"chiaroscuro", why:"his native language" },
    { t:"movement", id:"dutch-golden-age", why:"the market he outgrew" }],
  coords: { F:-80, D:35, E:25, C:0, M:-20 },
  arc: [
    { y:"1606–31", t:"The miller's son",
      text:"Ninth child of a Leiden miller, enrolled at the university at fourteen and gone within months — apprenticed to painters instead. By twenty-five, the statesman-poet Constantijn Huygens is telling anyone who will listen that a miller's boy has out-painted the ancients. Amsterdam sends for him." },
    { y:"1632", t:"Anatomy of a debut",
      text:"His first big Amsterdam commission turns the surgeons' guild's annual dissection into theatre — nobody poses, everybody leans in, and the corpse of a hanged robber gets the best light. He is twenty-six, and the city's merchant class forms a line at his door.",
      works:["the-anatomy-lesson"] },
    { y:"1634–42", t:"Saskia and the spending",
      text:"He marries Saskia van Uylenburgh, his dealer's cousin, and paints her as Flora, as Danaë, as everything. Money pours in and straight back out — a grand house on the Breestraat, weapons, costumes, coral, exotic armor: props for paintings, and a bankruptcy assembling itself in slow motion.",
      works:["the-storm-on-the-sea-of-galilee","danae-rembrandt"] },
    { y:"1642", t:"The Night Watch, the dark year",
      text:"He blows the militia group portrait apart — drums, muskets, motion, a golden girl in the crowd — and delivers the most famous painting in Dutch history the same year Saskia dies at twenty-nine, months after their son Titus is born. The grandest canvas and the worst year arrive together.",
      works:["the-night-watch"] },
    { y:"1649–54", t:"Hendrickje",
      text:"His housekeeper Hendrickje Stoffels becomes his common-law wife; the church council summons her — not him — for 'living in sin with Rembrandt the painter' while pregnant. He answers in paint: Bathsheba with a real body and an unreadable ache, Hendrickje's face on a queen's dilemma.",
      works:["bathsheba-at-her-bath"] },
    { y:"1656", t:"The inventory",
      text:"The debts win. The house, the Roman busts, the Japanese armor, his own collection of his own etchings — all catalogued and auctioned off over three years. The insolvency inventory survives, 363 lots long, one of the great documents of an artist's appetite. He moves to a rented house across town." },
    { y:"1662", t:"The comeback commission",
      text:"The cloth guild's sampling officials want a group portrait; the bankrupt delivers the calmest masterpiece of the century — five men glancing up from their ledger as if you had just opened the door. When he wants the old magic, it is all still there. Increasingly, he wants something rougher instead.",
      works:["syndics-of-the-drapers-guild"] },
    { y:"1663–68", t:"Outliving everyone",
      text:"Hendrickje dies in a plague year; Titus at twenty-seven, months after his wedding. The late self-portraits — paint thick as stucco, lit like verdicts — record all of it without an ounce of self-pity. In one, he stands before two painted circles that no one has ever conclusively explained.",
      works:["self-portrait-with-two-circles"] },
    { y:"1665–69", t:"The tenderest endgame",
      text:"Nearly alone at the end, he paints the gentlest things of his century: a couple's four hands saying belonging, a father's mismatched hands on a returned son's shoulders. He dies in October 1669 and is buried in a rented, unmarked church grave — owning, by the record, his painting tools and little else.",
      works:["the-jewish-bride","the-return-of-the-prodigal-son","self-portrait-at-63"] }
  ] },

"johannes-vermeer": {
  why: "Thirty-some paintings, mostly one quiet room — and within that whisper, the most perfect light in Western art. Vermeer made stillness an event: a woman reading a letter carries the tension other painters need battles for. Forgotten for two centuries, he now defines what 'luminous' means.",
  lookFor: ["Daylight entering from a window at left","Tiny pearls of thick paint on highlights","Maps and paintings hung as silent commentary","One gesture, suspended forever"],
  goNext: [
    { t:"artist", id:"vilhelm-hammershoi", why:"the same silence, painted grey" },
    { t:"artist", id:"frans-hals", why:"the loud opposite of the Golden Age" },
    { t:"work", id:"girl-with-a-pearl-earring", why:"five strokes make the pearl" },
    { t:"movement", id:"dutch-golden-age", why:"his small, deep pond" }],
  coords: { F:-90, D:-60, E:-20, C:-35, M:-85 },
  arc: [
    { y:"1632–53", t:"The innkeeper's son",
      text:"Born in Delft to a silk-weaver who kept an inn and dealt paintings on the side. At twenty he marries Catharina Bolnes, likely converting to Catholicism for it, and moves into the house of his formidable mother-in-law, Maria Thins — where he will paint nearly everything he ever paints." },
    { y:"1653", t:"Master without a master",
      text:"He registers as a master in Delft's Guild of Saint Luke — too broke to pay the full entry fee at once. No document names his teacher; no drawing by his hand survives. The most studied painter of domestic light arrives in history almost without a paper trail." },
    { y:"c. 1657–60", t:"Turning to the window",
      text:"He abandons big biblical histories for what was waiting at home: a maid pouring milk as if performing a sacrament, the houses across the street on an ordinary morning. The subject matter shrinks to a room; the ambition quietly becomes enormous.",
      works:["the-milkmaid","the-little-street"] },
    { y:"c. 1660–61", t:"The view of home",
      text:"His one great cityscape: Delft seen across the harbor, half in cloud shadow, sunlight breaking on the far bank — a town still rebuilding from the gunpowder explosion that had flattened a quarter of it in 1654. Painted with dots of raised light a camera would envy.",
      works:["view-of-delft"] },
    { y:"c. 1662–65", t:"The quiet theatre",
      text:"Women read letters, weigh pearls, turn toward us out of nowhere. His neighbours elect him headman of the painters' guild — twice — while most of his output goes to a single Delft patron, which is why almost nobody else in Europe knows his name.",
      works:["woman-in-blue","girl-with-a-pearl-earring","the-concert"] },
    { y:"c. 1666–68", t:"The one he kept",
      text:"The Art of Painting — his largest, slowest interior, painting itself as history's equal — never leaves the house. Through debt, through eleven children, through everything, he refuses to sell it. After his death, his widow tries desperately to keep it from the creditors.",
      works:["the-art-of-painting"] },
    { y:"1668–69", t:"The scientists",
      text:"Two small canvases of men among globes, charts and light: The Astronomer and The Geographer, possibly modeled by Antonie van Leeuwenhoek, the Delft draper who was busy inventing microbiology a few streets away — and who would later be executor of Vermeer's bankrupt estate.",
      works:["the-astronomer","the-geographer"] },
    { y:"1672–75", t:"The disaster year",
      text:"The Rampjaar: France invades and the Dutch art market simply stops. Vermeer, who dealt paintings as well as making them, sells nothing on either count. In December 1675 he goes, in his widow's words, 'from healthy to dead in a day and a half' — at forty-three, insolvent.",
      works:["the-lacemaker"] },
    { y:"1696–1866", t:"Vanished, then found",
      text:"Twenty-one Vermeers scatter at one Amsterdam auction in 1696, and for two centuries his pictures pass under other men's names. In 1866 the French critic Théophile Thoré-Bürger publishes the essays that resurrect him as the 'Sphinx of Delft.' Some thirty-six paintings survive; every one is now an event." }
  ] },

"diego-velazquez": {
  why: "Velázquez painted what was actually there — air included. Popes muttered 'too true'; Impressionists called him the painter of painters. Las Meninas turned looking itself into the subject, and his feathery late strokes, meaningless up close and alive at distance, taught Manet everything.",
  lookFor: ["Strokes that dissolve when you step close","Air and distance rendered between figures","Mirrors and canvases inside the picture","Silver-grey harmonies instead of loud color"],
  goNext: [
    { t:"artist", id:"edouard-manet", why:"the heir who said so" },
    { t:"artist", id:"francis-bacon", why:"the pope, screamed" },
    { t:"work", id:"las-meninas", why:"painting's supreme riddle" },
    { t:"artist", id:"francisco-goya", why:"the court, one century darker" }],
  coords: { F:-85, D:20, E:20, C:15, M:45 },
  arc: [
    { y:"1599–1617", t:"Seville apprentice",
      text:"Apprenticed at eleven to Francisco Pacheco — a modest painter but a superb teacher and connector. At eighteen Velázquez passes the guild exam; at nineteen he marries Pacheco's daughter Juana. His father-in-law will later write, without embarrassment, that the pupil overtook every master in Spain." },
    { y:"1618–22", t:"Kitchen theology",
      text:"His Seville canvases ennoble what nobody painted: an old woman frying eggs, a waterseller, servants at work — everyday life given the gravity of an altarpiece, every clay jug painted like a portrait. He is barely out of his teens and already painting matter better than anyone alive.",
      works:["old-woman-frying-eggs"] },
    { y:"1623", t:"The king's painter",
      text:"One portrait of the eighteen-year-old Philip IV is enough: Velázquez is named court painter at twenty-four, and the king reportedly resolves that no one else shall paint him from life again. The two will grow old together, a few rooms apart, for thirty-seven years." },
    { y:"1628–31", t:"Rubens, then Rome",
      text:"Rubens arrives at court, befriends him, and tells him plainly to see Italy. First he answers the visit with The Triumph of Bacchus — a god carousing among leathery Spanish drinkers — then leaves for Rome, where the Forge of Vulcan trades myth's polish for workshop sweat.",
      works:["the-triumph-of-bacchus","the-forge-of-vulcan"] },
    { y:"1634–35", t:"Victory without a boast",
      text:"For the new palace he paints the Surrender of Breda: the defeated commander offers the key, and the victor's hand lands not on a sword but on his enemy's shoulder. In a century of gloating battle pictures, Velázquez paints war as two tired men being courteous.",
      works:["the-surrender-of-breda"] },
    { y:"c. 1647–51", t:"A Venus in Inquisition Spain",
      text:"Somewhere between Madrid and Rome he paints the only nude of his that survives — Venus with her back turned, studying us in a blurred mirror. In Inquisition Spain, nudes could end careers; this one stayed in private cabinets for centuries and was slashed by a suffragette in 1914.",
      works:["rokeby-venus"] },
    { y:"1649–51", t:"Rome: too true",
      text:"Sent to Italy to buy art for the king, he stays to make it: first Juan de Pareja, his enslaved assistant, painted so alive that Rome gasped — Velázquez signed Pareja's freedom months later — then Innocent X, who looked at his own portrait and reportedly muttered 'troppo vero.'",
      works:["juan-de-pareja","portrait-of-innocent-x"] },
    { y:"1656", t:"The painting about painting",
      text:"Las Meninas: the infanta, her dwarfs, a dog, a mirror holding the king and queen, and the painter himself at a canvas we never see. Three centuries of arguments about who is looking at whom begin here. Nearby hangs its sister riddle, the Spinners, myth hidden in a tapestry workshop.",
      works:["las-meninas","las-hilanderas"] },
    { y:"1658–60", t:"The red cross",
      text:"He spends his last years pursuing a knighthood in the Order of Santiago — 148 witnesses examined to prove a painter could be noble. In 1660 he organizes the royal wedding pageant on the French border, comes home exhausted, and dies within weeks. The red cross on his chest in Las Meninas was added afterward — by legend, at the king's own order." }
  ] },

"francisco-goya": {
  why: "No artist travelled further in one lifetime: sunny tapestry cartoons to the Black Paintings on his own dining-room wall. Goya invented war art without heroes, satire without safety, and nightmare without mythology. Modern art's conscience — and its insomnia — start with him.",
  lookFor: ["Black used as a color, not an absence","Crowd faces smeared into masks","Violence shown without glory or rescue","Late beasts painted straight onto plaster"],
  goNext: [
    { t:"work", id:"saturn-devouring-his-son", why:"the dining room in question" },
    { t:"artist", id:"otto-dix", why:"Der Krieg answers the Disasters" },
    { t:"artist", id:"edouard-manet", why:"the executions, restaged" },
    { t:"movement", id:"romanticism", why:"his uneasy label" }],
  coords: { F:-70, D:80, E:50, C:15, M:0 },
  arc: [
    { y:"1746–74", t:"The Aragonese climber",
      text:"A gilder's son from a stone village near Zaragoza, twice rejected by the royal academy, so he takes the other road: Italy on his own money, then marriage to Josefa Bayeu — sister of the court painter. Talent gets you noticed in Madrid; in-laws get you through the door." },
    { y:"1775–92", t:"Picnics for palaces",
      text:"For seventeen years he designs tapestry cartoons for royal walls — parasols, dances, kite days, majas flirting in the sun. It looks like harmless décor, and it is also a complete education in Spanish life, filed away by the sharpest pair of eyes in the country.",
      works:["the-parasol"] },
    { y:"1793", t:"Silence",
      text:"An illness nobody has ever securely diagnosed — lead poisoning and autoimmune disease are the modern guesses — nearly kills him at forty-six and leaves him permanently, totally deaf. The courtier keeps his job and his smile. The painter starts working for himself, and the work turns inward at once." },
    { y:"1799", t:"The sleep of reason",
      text:"Los Caprichos: eighty etchings flaying superstition, vanity, clergy and cruelty, sold out of a perfume shop and withdrawn within days — reportedly before the Inquisition could take a formal interest. Plate 43 is the thesis: a sleeping man mobbed by owls and bats, reason abandoned to monsters.",
      works:["the-sleep-of-reason","witches-sabbath"] },
    { y:"1800–05", t:"First Painter, private nudes",
      text:"The official summit: First Court Painter, unveiling the royal family with almost reckless honesty. The private summit: for the prime minister's hidden cabinet, a maja naked and the same maja clothed — a hinged pair, one made to swing over the other. The Inquisition will eventually ask him about that.",
      works:["charles-iv-of-spain-and-his-family","the-naked-maja","the-clothed-maja"] },
    { y:"1808–14", t:"The war",
      text:"Napoleon's armies occupy Spain; Goya keeps his head down, sketches what he sees, and says nothing for six years. When the French are gone he answers with the Second and Third of May — uprising and reprisal, the firing squad as machine — and invents how war would be pictured from then on.",
      works:["the-second-of-may-1808","the-third-of-may-1808"] },
    { y:"1819–23", t:"The house of the deaf man",
      text:"Deaf, ill and seventy-three, he buys a farmhouse outside Madrid and paints directly onto its plaster walls: Saturn devouring, witches assembling, a dog's head in a void. No commission, no titles, no intention that anyone should see them. The Black Paintings are the most private great pictures ever made.",
      works:["saturn-devouring-his-son","the-dog"] },
    { y:"1820", t:"Gratitude",
      text:"After another near-fatal illness he paints himself limp in the arms of Dr Arrieta, who steadies the medicine glass at his lips, and inscribes it like a votive tablet: in gratitude to the friend whose skill saved his life. The hardest eye in Europe, gone soft exactly once.",
      works:["self-portrait-with-dr-arrieta"] },
    { y:"1824–28", t:"Still learning",
      text:"At seventy-eight he self-exiles to Bordeaux among Spain's liberals, takes up the brand-new craft of lithography, and captions a late drawing of a bearded ancient hobbling on two sticks 'Aún aprendo' — I am still learning. He dies at eighty-two, the hinge between the old masters and everything modern." }
  ] },

"katsushika-hokusai": {
  why: "Hokusai gave the world its most reproduced image and Japan its restless genius — thirty name changes, ninety addresses, 'mad about painting' to the last. The Great Wave taught the West that flatness, cropping and pattern could carry monumental force. Monet and Van Gogh collected him like scripture.",
  lookFor: ["Waves with claws, foam like snowflakes","Mount Fuji hiding somewhere small","Imported Prussian blue everywhere","Motion caught mid-gesture, never posed"],
  goNext: [
    { t:"artist", id:"utagawa-hiroshige", why:"the rival who painted weather" },
    { t:"artist", id:"vincent-van-gogh", why:"the most devoted student" },
    { t:"work", id:"the-great-wave-off-kanagawa", why:"the image itself" },
    { t:"technique", id:"woodblock", why:"the medium of multiplication" }],
  coords: { F:-55, D:40, E:30, C:-25, M:0 },
  arc: [
    { y:"1760–78", t:"Edo apprentice",
      text:"Born in Edo's Katsushika district and raised in a mirror-polisher's household, he is cutting printing blocks by fourteen and at eighteen enters the studio of Katsukawa Shunshō, the master of actor portraits. He learns the trade by flooding the market with it." },
    { y:"1779–1805", t:"Thirty names",
      text:"Expelled from the studio after his master's death, he reinvents himself relentlessly — over thirty art-names across his life, a new one for each new style. For a festival crowd he paints a Daruma the size of a building with a broom; for the shogun he wins a contest by dragging an inked rooster's feet across a blue stream: autumn leaves on a river." },
    { y:"1814", t:"The Manga",
      text:"He begins publishing the Hokusai Manga — sketch encyclopedias of everything: wrestlers and ghosts, waterfalls, noses, gods, cats, carpenters' knots. Four thousand drawings, fifteen volumes, a bestseller for decades and, eventually, Europe's first textbook of Japanese drawing.",
      works:["hokusai-manga"] },
    { y:"c. 1830–32", t:"The mountain, thirty-six ways",
      text:"In his seventies, with the newly affordable Prussian blue, he makes Thirty-six Views of Mount Fuji — the sacred peak framed by commerce, weather and one monstrous wave. The Great Wave will become the most reproduced image in the history of art; Red Fuji is its silent twin.",
      works:["the-great-wave-off-kanagawa","red-fuji","black-fuji"] },
    { y:"1832–34", t:"Water studies",
      text:"He follows the Views with waterfalls that fall like living beings, bridges, birds and the great flower prints — a fisherman alone on a rock at Kajikazawa, travelers losing their papers to the wind at Ejiri. Landscape print-making, a minor genre, is suddenly the main event.",
      works:["amida-falls","kajikazawa","ejiri-in-suruga","poppies-hokusai"] },
    { y:"1839", t:"Fire and eclipse",
      text:"A studio fire devours his drawings and equipment; the younger Hiroshige's travel prints capture the market; a wastrel grandson gambles away what money there was. In his eighties he is effectively poor — and drawing, by his own account, a lion exorcism sketch every morning." },
    { y:"1834–49", t:"Old man crazy to paint",
      text:"He signs his late work Gakyō Rōjin Manji — 'old man mad about painting' — and writes the famous postscript: nothing he drew before seventy counts; at eighty he'll have made some progress; at ninety he'll grasp the secret of things; at one hundred and ten, every dot and line will be alive." },
    { y:"1849", t:"Five more years",
      text:"On his deathbed at eighty-nine, the reported plea: 'If heaven had granted me five more years, I could have become a real painter.' He is buried in Edo under his final name; his epitaph might as well be the postscript." },
    { y:"1856–", t:"Japonisme",
      text:"Within years of his death — the tale says via prints found as packing paper in a Paris crate — the Manga and the Wave detonate in Europe. Monet papers Giverny with Japanese prints, Debussy puts the Wave on La Mer's cover, Van Gogh copies the compositions outright. Edo's tradesman becomes the world's Japan." }
  ] },

"jmw-turner": {
  why: "Turner pushed landscape from scenery to cataclysm and then further — into pure vortices of light that contemporaries called unfinished and abstraction later called prophecy. He painted the industrial revolution as weather. Impressionism, and arguably Rothko, disembark from his boats.",
  lookFor: ["Light dissolving solid objects","Vortex compositions that pull you in","The sun stared at directly","Sea and storm as the main characters"],
  goNext: [
    { t:"artist", id:"claude-lorrain", why:"the idol he demanded to hang beside" },
    { t:"artist", id:"claude-monet", why:"the student of his dissolutions" },
    { t:"artist", id:"mark-rothko", why:"the sublime, abstracted" },
    { t:"movement", id:"romanticism", why:"his storm system" }],
  coords: { F:-40, D:75, E:65, C:-30, M:60 },
  arc: [
    { y:"1775–96", t:"The barber's boy",
      text:"Son of a Covent Garden barber who hung the boy's drawings in the shop window and sold them for shillings. Into the Royal Academy schools at fourteen; at twenty-one his first exhibited oil is already a manifesto — a moonlit sea that outshines the moon.",
      works:["fishermen-at-sea"] },
    { y:"1802–12", t:"Storm chaser",
      text:"He crosses the Alps sketching avalanches and gorges, and later watches a thunderstorm rake the Yorkshire hills, drawing on whatever paper was in his pocket. Out of it comes Hannibal: an army swallowed by a vortex of weather, history painting with the history nearly blown out of it.",
      works:["hannibal-crossing-the-alps"] },
    { y:"1819", t:"Italy floods in",
      text:"His first stay in Venice and Rome resets his eye: watercolours of lagoon light in which form is almost optional. The English topographer goes south and comes back a painter of atmospheres. From here on, the paint gets thinner, brighter and less negotiable." },
    { y:"1834–35", t:"London burns",
      text:"When the Houses of Parliament catch fire, Turner is in the crowd on the Thames, filling sketchbooks while the sky performs. The canvases that follow give the disaster the full sunset treatment — catastrophe as the best light show the century had yet staged.",
      works:["the-burning-of-the-houses"] },
    { y:"1839", t:"The last berth",
      text:"A Trafalgar veteran towed to the breaker's yard by a steam tug becomes his elegy for the age of sail — and, he seems to know, for his own era. He calls the picture his darling, refuses every buyer, and wills it to the nation.",
      works:["the-fighting-temeraire"] },
    { y:"1840–42", t:"The sea as verdict",
      text:"The Slave Ship turns a massacre for insurance money into a boiling golden sea that accuses everyone who admires it. Two years later, Snow Storm answers critics of his 'soapsuds and whitewash' — he claimed, tall tale or not, to have been lashed to a steamboat's mast to see it. 'I did not paint it to be understood.'",
      works:["slave-ship","snow-storm-steamboat"] },
    { y:"1844", t:"Painting velocity",
      text:"Rain, Steam and Speed: a train on Brunel's new railway charges out of a wet gold haze, a hare racing it down the track. Nobody had painted speed before — there had been no speed to paint. The nineteenth century finally gets its portrait.",
      works:["rain-steam-and-speed"] },
    { y:"c. 1845", t:"Dissolving",
      text:"In the late canvases — Norham Castle at sunrise above all — the objects nearly leave; what remains is colour breathing in light. He never exhibited them; many were found rolled in his studio. A century on, they would be hung beside Rothko without apology.",
      works:["norham-castle-sunrise"] },
    { y:"1851", t:"'The sun is God'",
      text:"He spends his last years incognito in Chelsea as 'Mr Booth,' the name of his landlady-companion, watching the river. He dies in December 1851 — the reported last words are the ones everyone wants to believe — leaving some 300 oils and 30,000 works on paper to Britain: the Turner Bequest." }
  ] },

"claude-monet": {
  why: "Monet chased fugitive light for sixty years and invented the modern series along the way — the same haystack, cathedral, pond, repainted as the hour turned. Impressionism carries his painting's name by accident and his stubbornness by design. The water lilies end where abstraction begins.",
  lookFor: ["Broken dabs of unmixed color","Shadows in color, never black","The same motif at different hours","Water doing half the painting's work"],
  goNext: [
    { t:"artist", id:"pierre-auguste-renoir", why:"the friend at La Grenouillère" },
    { t:"artist", id:"joan-mitchell", why:"his pond, her storm, same village" },
    { t:"work", id:"impression-sunrise", why:"the insult that named a movement" },
    { t:"movement", id:"impressionism", why:"the church he built" }],
  coords: { F:-45, D:-30, E:35, C:-70, M:-10 },
  arc: [
    { y:"1840–61", t:"The caricaturist meets the sky",
      text:"A Le Havre teenager earning good money on caricatures until the local marine painter Eugène Boudin drags him outdoors to paint air and water directly. Monet resisted, went once, and described it afterwards as a veil tearing: suddenly he understood what painting could be." },
    { y:"1865–70", t:"Camille and the trench",
      text:"He paints Camille Doncieux — model, lover, then wife over his family's objections — and thinks big: for Women in the Garden he digs a trench so the two-and-a-half-metre canvas can be cranked down to paint the top in the same outdoor light. The Salon shrugs; even his snow-bright Magpie is refused.",
      works:["women-in-the-garden","the-magpie"] },
    { y:"1869", t:"The frog pond",
      text:"Broke, he sets up beside Renoir at La Grenouillère, a bathing spot on the Seine, and between them they work out a shorthand for water in motion — broken touches of unmixed color that only resolve at a distance. Impressionism is invented in a few afternoons; the name comes later.",
      works:["la-grenouillere"] },
    { y:"1874", t:"An insult becomes a movement",
      text:"At the painters' first independent exhibition he hangs a Le Havre harbor at sunrise, titled almost offhandedly Impression. The critic Louis Leroy sneers that wallpaper in its embryonic state is more finished — and the insult sticks as a name. Within a decade, the joke is on the Salon.",
      works:["impression-sunrise"] },
    { y:"1875–79", t:"Steam and grief",
      text:"He paints Camille and their son on a windy rise, then a dozen canvases of the Gare Saint-Lazare — locomotives exhaling weather indoors. In 1879 Camille dies at thirty-two, and Monet, horrified at his own eye, catches himself studying the grays death fixes on her face. Light spares nothing.",
      works:["woman-with-a-parasol","gare-saint-lazare"] },
    { y:"1883", t:"Giverny",
      text:"He rents, and later buys, a pink farmhouse at Giverny and begins the real masterpiece: the garden. Flowerbeds laid out like loaded palettes, then a diverted stream, a pond, water lilies and a Japanese bridge — a motif farm, planted years before he intends to harvest it." },
    { y:"1890–94", t:"Painting time",
      text:"The grainstacks behind his house become a relay — canvases swapped as the light moves, frost-pink dawn to smoldering dusk. Fifteen hang together in 1891 and sell within days. Then thirty-odd façades of Rouen Cathedral, stone as a screen for passing hours. The subject is no longer the thing; it is time moving across the thing.",
      works:["grainstacks","rouen-cathedral-full-sunlight"] },
    { y:"1899–1926", t:"The pond swallows painting",
      text:"From the Japanese bridge to lily pads to pure reflection, the pond grows until the horizon leaves the canvas entirely. Cataracts redden his world for a decade — after surgery in 1923 he destroys canvases painted through the fog — while Clemenceau keeps him at the huge cycle promised to France the day after the armistice.",
      works:["bridge-over-a-pond-of-water-lilies","water-lilies-grandes-decorations"] },
    { y:"1927", t:"The oval rooms",
      text:"He dies in December 1926, at eighty-six, still revising his unfinished walls of water. Five months later the Grandes Décorations open in two oval rooms at the Orangerie — no horizon, no bank, no edge. Painting had followed him to the brink of abstraction; the next generation stepped over." }
  ] },

"vincent-van-gogh": {
  why: "Ten years, nine hundred paintings, one sale — then the whole world. Van Gogh turned brushwork into handwriting and color into confession; every stroke is signed by a nervous system. He is proof that painting can carry a life's entire voltage, and modern art's most loved cautionary saint.",
  lookFor: ["Directional strokes following forms like currents","Halos vibrating around lights and stars","Complementary colors set to collide","Paint thick enough to map with a finger"],
  goNext: [
    { t:"artist", id:"paul-gauguin", why:"nine weeks, one ear, lifelong letters" },
    { t:"artist", id:"jean-francois-millet", why:"'father Millet', copied twenty times" },
    { t:"work", id:"the-starry-night", why:"the asylum window, transfigured" },
    { t:"movement", id:"expressionism", why:"everything he made possible" }],
  coords: { F:-55, D:70, E:60, C:-45, M:-25 },
  arc: [
    { y:"1853–80", t:"The failures",
      text:"Art dealer (dismissed), teacher, bookseller, theology student (withdrew), lay missionary in the Borinage coalfields (relieved of duty, reportedly for excessive zeal — he gave away his clothes and slept on straw). At twenty-seven, with nothing left to fail at, he starts to draw. Ten years remain." },
    { y:"1885", t:"Peasants, painted with earth",
      text:"In Nuenen he paints five peasants around one dish by lamplight, in colors he compared to a dusty, unpeeled potato. He means it as his first masterpiece; a friend's critique of its anatomy ends the friendship for good. He never stops defending it.",
      works:["the-potato-eaters"] },
    { y:"1886–87", t:"Paris detonates the palette",
      text:"Two years with Theo in Montmartre: Impressionism, pointillism and Japanese prints hit in quick succession, and the Dutch mud brightens into strokes of pure color. He paints some two dozen self-portraits, partly because models cost money — the face in the mirror is the one sitter who never complains." },
    { y:"1888", t:"The yellow house",
      text:"Fifteen months in Arles, roughly two hundred paintings — sunflowers to decorate Gauguin's promised room, a café terrace glowing gas-orange against blue, his own bedroom painted flat and calm, he said, to rest the brain. He is burning through himself at the rate of a canvas every two days.",
      works:["sunflowers","cafe-terrace-at-night","the-bedroom","the-night-cafe"] },
    { y:"1888–89", t:"The ear",
      text:"Gauguin arrives in October; the shared studio curdles in nine weeks. On 23 December, after a quarrel, Vincent mutilates his left ear — how much of it is still debated — and delivers it to a woman at the local brothel. In January he paints himself bandaged, calm, studying the damage.",
      works:["self-portrait-with-bandaged-ear"] },
    { y:"1889", t:"Saint-Rémy",
      text:"He commits himself to the asylum at Saint-Rémy. Between crises — during one he ate paint — the view through the barred window becomes The Starry Night, the garden becomes irises, and for Theo's newborn son, named Vincent after him, he paints almond branches against a spring sky.",
      works:["the-starry-night","irises","almond-blossom"] },
    { y:"1890", t:"Seventy days in Auvers",
      text:"Released, he settles near Dr Gachet north of Paris and paints at a sprint — close to a canvas a day for seventy days. The wheatfields stretch horizontal and restless; he writes of 'sadness, extreme loneliness' in the same letter that calls the countryside healthy and fortifying.",
      works:["wheatfield-with-crows"] },
    { y:"1890", t:"The end",
      text:"On 27 July he walks out to the fields and is shot in the chest — by his own hand, by every accepted account. He dies two days later with Theo at the bedside. Theo, shattered, follows him within six months; they lie side by side at Auvers under matching ivy." },
    { y:"1891–1905", t:"Johanna builds the legend",
      text:"He had sold almost nothing — one confirmed painting in his lifetime. Theo's widow, Johanna van Gogh-Bonger, inherits some seven hundred works plus the letters, and spends decades exhibiting, translating and publishing until the failure of 1880 has become the most loved painter on earth." }
  ] },

"paul-cezanne": {
  why: "Cézanne wanted to make Impressionism 'solid and durable like museum art' — and accidentally drafted the twentieth century. Form built from color patches, perspective bent by honesty, one mountain repainted sixty times. Matisse and Picasso split the inheritance and called him father of us all.",
  lookFor: ["Tabletops tilting toward the viewer","Form built from parallel patch-strokes","Outlines restated three or four times","The same mountain, again, differently"],
  goNext: [
    { t:"artist", id:"pablo-picasso", why:"heir number one" },
    { t:"artist", id:"nicolas-poussin", why:"'Poussin, redone from nature'" },
    { t:"artist", id:"camille-pissarro", why:"the humble teacher" },
    { t:"movement", id:"cubism", why:"what the patches became" }],
  coords: { F:-60, D:-10, E:60, C:20, M:-15 },
  arc: [
    { y:"1839–61", t:"The banker's son",
      text:"Aix-en-Provence: a domineering banker father, law school endured, and a schoolboy friendship with Émile Zola — they swim the Arc, trade poems, and promise each other Paris. In 1861 the father finally relents, and Cézanne takes his allowance north to fail the entrance exam to the École des Beaux-Arts." },
    { y:"1862–70", t:"The black period",
      text:"Thick paint troweled with the palette knife, murders, orgies and portraits like slabs — he calls the manner couillarde, roughly 'ballsy.' The Salon rejects him annually; he submits anyway, he says, so they can refuse him properly. Manet finds him coarse. He cultivates it." },
    { y:"1872–74", t:"Learning patience",
      text:"At Pontoise and Auvers, painting shoulder to shoulder with the patient Pissarro — 'humble and colossal,' Cézanne called him — the black period lightens into ordered strokes. The House of the Hanged Man hangs at the first Impressionist exhibition in 1874 and is mocked with all the rest.",
      works:["house-of-the-hanged-man"] },
    { y:"1878–86", t:"The break",
      text:"He hides Hortense Fiquet and their son from his father for years while painting her with a still life's patience — she sat, by one count, twenty-nine times. In 1886 Zola publishes a novel about a failed painter too plainly modeled on him; barely a word passes between the friends again. That year his father dies, leaving him rich and free.",
      works:["madame-cezanne"] },
    { y:"1887–95", t:"The mountain",
      text:"Mont Sainte-Victoire, over eighty times: from his sister's terrace, from the Bibémus quarry, from the road. 'Painting from nature is not copying the object,' he insists; 'it is realizing one's sensations' — rebuilding what the eye receives, plane by plane, until geology and geometry agree.",
      works:["mont-sainte-victoire"] },
    { y:"1890–95", t:"Peasants at cards",
      text:"Farmhands from the family estate sit for the Card Players — five versions, each with fewer figures and less anecdote, until two men and a bottle carry the weight of a temple pediment. Nobody cheats, nobody wins; concentration itself becomes the subject.",
      works:["the-card-players"] },
    { y:"1895", t:"The apples conquer Paris",
      text:"The dealer Ambroise Vollard gives the near-unknown fifty-six-year-old his first solo show. Younger painters are staggered; Pissarro, Degas and Monet buy. The tilted tabletops that look like mistakes — each object seen from its own angle — turn out to be the exit from four hundred years of perspective.",
      works:["the-basket-of-apples","still-life-with-plaster-cupid"] },
    { y:"1898–1906", t:"The bathers",
      text:"In a purpose-built studio he works on monumental bathers — nudes from memory and old drawings, since models scandalized Aix — arranging bodies into blue cathedral arches. Unfinished patches show raw canvas; he no longer minds. 'I am the primitive of a new art,' he reportedly said.",
      works:["the-large-bathers"] },
    { y:"1906", t:"Dying on the motif",
      text:"Caught by a storm while painting outdoors in October 1906, he collapses on the road and is brought home on a laundry cart. He is back at the easel the next day, and dead of pneumonia within the week. A year later, his memorial retrospective detonates under Picasso and Braque: Cubism calls him 'the father of us all.'" }
  ] },

"gustav-klimt": {
  why: "Klimt armored desire in ornament: real gold leaf, Byzantine geometry, bodies dissolving into pattern. His Vienna scandalized itself on him and then couldn't live without him. The Kiss made the sacred and the erotic share one halo — Art Nouveau's summit and modern portraiture's glamour blueprint.",
  lookFor: ["Actual gold leaf emitting, not reflecting","Pattern swallowing bodies whole","Rectangles for him, circles for her","Faces in closed-eye ecstasy"],
  goNext: [
    { t:"artist", id:"egon-schiele", why:"the protégé who tore the gold off" },
    { t:"work", id:"the-kiss", why:"the summit" },
    { t:"technique", id:"gold-leaf", why:"the inheritance from Byzantium" },
    { t:"movement", id:"vienna-secession", why:"his gilded rebellion" }],
  coords: { F:-55, D:15, E:35, C:-45, M:0 },
  arc: [
    { y:"1862–83", t:"The gilder's son",
      text:"Born outside Vienna to a gold engraver who never quite made a living — the gold arrived early, the money didn't. At fourteen he enters the School of Applied Arts; with his brother Ernst and a friend he forms a company painting theatre ceilings, murals and museum staircases: prodigies for hire." },
    { y:"1886–92", t:"The establishment's darling",
      text:"Ceilings for the Burgtheater, the grand staircase of the Kunsthistorisches Museum, a Golden Order of Merit from the Emperor — at thirty he is official Vienna's favorite decorator. Then 1892 takes both his father and his brother Ernst, and the safe career quietly dies with them." },
    { y:"1897", t:"Secession",
      text:"He leads nineteen artists out of the conservative Künstlerhaus and founds the Vienna Secession, serving as its first president. Over the door of their new temple goes the creed: 'To every age its art, to art its freedom.' Vienna's establishment painter is now its chief heretic." },
    { y:"1900–05", t:"The faculty paintings war",
      text:"His ceiling allegories for the university — Philosophy, Medicine, Jurisprudence — replace triumphant reason with drifting bodies and void. Eighty-seven professors petition against them; the press calls it painted madness. Klimt repays the state fee, swears off public commissions, and the canvases end up burned by retreating SS troops in 1945.",
      works:["judith-i"] },
    { y:"1902", t:"The Beethoven Frieze",
      text:"For the Secession's Beethoven exhibition he paints a thirty-four-metre frieze straight onto plaster: the longing for happiness sails past hostile powers — a giant ape, gorgons, Excess — toward a choir-of-angels embrace. Meant to be temporary, mocked as obscene, it is now the building's permanent treasure.",
      works:["beethoven-frieze"] },
    { y:"1903–09", t:"The golden phase",
      text:"Two trips to Ravenna's mosaics teach him what gold can do to space. Adele Bloch-Bauer becomes a Byzantine icon, Danaë sleeps in a rain of gold, and The Kiss — bought by Austria straight from the exhibition — turns embrace into ornament. The gilder's son has made the family trade immortal.",
      works:["adele-bloch-bauer-i","the-kiss","danae-klimt","tree-of-life-stoclet"] },
    { y:"1904–16", t:"Emilie and the Attersee",
      text:"He never marries. His life's companion is the fashion designer Emilie Flöge — muse, business partner, the woman in the reform dresses he reportedly helped design — and their summers on the Attersee produce the square lake landscapes, painted, the story goes, from a rowboat with opera glasses.",
      works:["emilie-floge"] },
    { y:"1910–15", t:"Death watches Life",
      text:"His grand allegory Death and Life takes first prize at the 1911 Rome exhibition: a tower of sleeping humanity watched by a grinning skeleton in a robe of crosses. After his mother dies in 1915, he repaints the gold background a cold blue-grey — the golden phase is over.",
      works:["death-and-life"] },
    { y:"1918", t:"The year Vienna's art died",
      text:"A stroke in January, pneumonia in February — dead at fifty-five with canvases unfinished, Schiele sketching him in the morgue. Within the year the flu and the collapsing empire also take Schiele, Otto Wagner and Koloman Moser: Vienna's entire modern movement, gone in twelve months." }
  ] },

"edvard-munch": {
  why: "Munch painted states of mind as if they were weather — jealousy, illness and dread given color and a horizon. The Scream became modern anxiety's logo, but the whole Frieze of Life pulses with the same voltage. German Expressionism is his echo chamber.",
  lookFor: ["Aura lines radiating from figures","Faces simplified to masks","Blood-dusk skies and long shadows","The same traumas repainted for decades"],
  goNext: [
    { t:"artist", id:"ernst-ludwig-kirchner", why:"the echo in Berlin" },
    { t:"artist", id:"vincent-van-gogh", why:"the other painter of nerves" },
    { t:"work", id:"the-scream", why:"the logo of dread" },
    { t:"movement", id:"expressionism", why:"the movement he seeded" }],
  coords: { F:-55, D:85, E:55, C:0, M:-15 },
  arc: [
    { y:"1868", t:"The sickroom",
      text:"His mother dies of tuberculosis when Edvard is five; his sister Sophie follows when he is thirteen. 'Illness, insanity and death were the black angels that kept watch over my cradle' — the inheritance he never escaped, and the one he painted from for sixty years." },
    { y:"1886", t:"The first scandal",
      text:"He abandons engineering for art and falls in with Kristiania's bohemians, whose commandment is 'write your own life.' He obeys in paint: The Sick Child, scraped and reworked for a year, is jeered at the Autumn Exhibition as an unfinished smudge. He later called it the birth of everything he did.",
      works:["the-sick-child"] },
    { y:"1889", t:"The Saint-Cloud vow",
      text:"News of his father's death reaches him in France, where he has gone on a state scholarship. Alone in Saint-Cloud he writes the manifesto that ends naturalism for him: 'No more interiors with men reading and women knitting. I will paint living people who breathe and feel and suffer and love.'" },
    { y:"1892", t:"The Berlin affair",
      text:"The Verein Berliner Künstler invites the young Norwegian to exhibit, sees the paintings, and votes to shut the show within a week. The scandal makes his name across Germany overnight; he stays, drinking with Strindberg at the Black Piglet and painting the dread of a crowd at dusk.",
      works:["evening-on-karl-johan"] },
    { y:"1893–95", t:"The Frieze of Life",
      text:"In three furious years he paints the core of his lifelong cycle on love, jealousy and death — The Scream, Madonna, Anxiety, Puberty — conceived, he said, to be seen together like a symphony. Modern art gets its face; Munch gets a reputation as a dangerous man.",
      works:["the-scream","madonna-munch","anxiety-munch","puberty-munch"] },
    { y:"1902", t:"The revolver",
      text:"The long, corrosive affair with Tulla Larsen ends in his studio with a gunshot that mangles a finger of his left hand. He had already painted them both into The Dance of Life — her in white hope on the left, her in black mourning on the right, himself in the middle, dancing with someone else.",
      works:["the-dance-of-life"] },
    { y:"1908", t:"The collapse",
      text:"Alcohol, brawls and what he called 'my enemies' — years of unraveling end in Dr. Jacobson's Copenhagen clinic, with electrotherapy and eight months of rest. He credited the clinic with saving his life; sobriety brightened his palette and never touched his subjects." },
    { y:"1911", t:"The Sun",
      text:"Home in Norway for good, he throws himself at the competition to decorate the University of Oslo's ceremonial hall — and the painter of screams answers his breakdown with a sunrise, four and a half metres tall, installed after five years of committee wars in 1916.",
      works:["the-sun-munch"] },
    { y:"1937–44", t:"Degenerate, then immortal",
      text:"The Nazis brand his work degenerate and seize 82 pieces from German museums; occupied Norway watches him refuse every overture from the regime. He dies in January 1944, still painting himself honestly — old, thin, standing between the clock and the bed — and wills over a thousand paintings to the city of Oslo.",
      works:["between-the-clock-and-the-bed"] }
  ] },

"henri-matisse": {
  why: "Matisse freed color from description twice — first with the Fauves' wild canvases, then, bedridden at eighty, with scissors and painted paper. His lifelong subject was joy treated with total seriousness. Half of modern art argues with Picasso; the other half convalesces with Matisse.",
  lookFor: ["Color choices that describe feeling, not fact","One arabesque line doing a figure's work","Flat patterned interiors without shadows","Late shapes cut, not drawn"],
  goNext: [
    { t:"artist", id:"pablo-picasso", why:"the North Pole to his South" },
    { t:"artist", id:"gustave-moreau", why:"the teacher who allowed it" },
    { t:"artist", id:"paul-signac", why:"the dots that lit the fuse" },
    { t:"movement", id:"fauvism", why:"the cage of wild beasts" }],
  coords: { F:-50, D:0, E:55, C:-60, M:10 },
  arc: [
    { y:"1869–90", t:"The paintbox in bed",
      text:"Born above his family's grain shop in northern France, Matisse trains for the law and works as a clerk. At twenty, recovering from appendicitis, he receives a paintbox from his mother. Painting feels like paradise; within a year he abandons the respectable career prepared for him." },
    { y:"1891–1904", t:"Learning to unlearn",
      text:"Parisian academies teach him the old masters, while Gustave Moreau teaches something rarer: permission. Matisse copies Chardin in the Louvre, absorbs Cézanne's structure and Signac's divided color, accumulates debts buying modern pictures, and slowly replaces correct description with color chosen for its emotional voltage." },
    { y:"1905", t:"The cage of wild beasts",
      text:"A summer beside André Derain at Collioure detonates his palette. At the Salon d'Automne, Woman with a Hat and the open-window views provoke the critic Louis Vauxcelles to cry 'Donatello among the wild beasts.' Fauvism gets its name from the insult; Matisse becomes its unnervingly calm leader.",
      works:["woman-with-a-hat","open-window-collioure"] },
    { y:"1905–06", t:"Joy as a manifesto",
      text:"The Joy of Life gathers dancers, lovers and musicians into a landscape unconcerned with believable scale or color. Leo and Gertrude Stein buy it after a long argument. Picasso studies it intensely, then answers with Les Demoiselles d'Avignon: modern painting's great rivalry has found its first battlefield.",
      works:["the-joy-of-life"] },
    { y:"1909–11", t:"Walls for Shchukin",
      text:"The Russian collector Sergei Shchukin commissions two immense panels for a Moscow staircase. Dance reduces five bodies to rhythm against blue and green; Music answers in severe stillness. Soon The Red Studio dissolves the room itself into vermilion, leaving paintings and furniture afloat like memories.",
      works:["the-dance-matisse","the-red-studio"] },
    { y:"1912–16", t:"Morocco, then austerity",
      text:"Two Moroccan journeys deepen his appetite for patterned space, saturated light and the calm attention embodied by Goldfish. The First World War brings a harder interval: The Piano Lesson compresses family, window and instrument into an icy geometry, proof that Matisse's promised pleasure was never simple decoration.",
      works:["goldfish-matisse","the-piano-lesson"] },
    { y:"1917–39", t:"The Nice interiors",
      text:"He settles in hotel rooms and apartments along the Riviera, staging odalisques among striped cloth, screens, flowers and open windows. Critics mistake the apparent ease for retreat. Matisse is testing how little depth a room needs, and how pattern can hold a figure without imprisoning it." },
    { y:"1941–52", t:"A second life with scissors",
      text:"Cancer surgery leaves him frequently confined to bed or wheelchair. He calls the recovery a second life and begins cutting shapes from assistants' painted paper — drawing directly into color with scissors. Blue Nude II turns the laborious pose of a body into four blue islands held by white air.",
      works:["blue-nude-ii"] },
    { y:"1948–54", t:"The chapel and the Snail",
      text:"He designs the Vence chapel as a total work — windows, vestments, ceramics, black line and colored light — then pushes the cut-outs to room scale. The Snail spirals through blocks of pure color. Matisse dies in Nice at eighty-four, still arranging paper from bed.",
      works:["the-snail"] }
  ] },

"pablo-picasso": {
  why: "Picasso is the century in one career: blue grief, rose circuses, Cubism's earthquake, Guernica's scream, and fifty thousand works of restless everything. He didn't have a style; he had appetites. Every argument about what art is allowed to do passes through him.",
  lookFor: ["Faces showing profile and front at once","Period shifts you can date by color","African mask geometry in the features","Bulls, minotaurs and self-mythology"],
  goNext: [
    { t:"artist", id:"georges-braque", why:"roped together on the cliff of Cubism" },
    { t:"artist", id:"henri-matisse", why:"the lifelong duel" },
    { t:"artist", id:"el-greco", why:"the flame under Les Demoiselles" },
    { t:"movement", id:"cubism", why:"the earthquake itself" }],
  coords: { F:-40, D:45, E:80, C:30, M:20 },
  arc: [
    { y:"1881–1901", t:"Prodigy and loss",
      text:"Pablo Ruiz Picasso draws before he can properly speak, outpaces his artist father, and enters Barcelona's academy at thirteen. In bohemian Paris, the suicide of his friend Carles Casagemas turns precocious virtuosity inward. Blue floods the paintings; poverty, blindness and isolation become his first adult language." },
    { y:"1901–04", t:"The blue years",
      text:"Moving between Barcelona and Paris, he paints gaunt bodies in cold rooms with a narrow blue-green range. The Old Guitarist bends age and grief into a single angular silhouette. These works are technically traditional but emotionally merciless — sympathy stripped of anecdote or rescue.",
      works:["the-old-guitarist"] },
    { y:"1904–06", t:"The circus turns rose",
      text:"At the ramshackle Bateau-Lavoir studio, a relationship with Fernande Olivier warms the palette. Harlequins, acrobats and wandering performers become stand-ins for artists living outside ordinary society. The Family of Saltimbanques gathers them together while preserving the distance between every figure.",
      works:["family-of-saltimbanques"] },
    { y:"1907", t:"The room that broke painting",
      text:"Months of studies, African and Iberian sculpture, Cézanne and El Greco converge in Les Demoiselles d'Avignon. Five bodies face the viewer like sharpened masks; space splinters around them. Friends recoil, Matisse is furious, and Picasso hides the canvas for years. Cubism begins in that hostile room.",
      works:["les-demoiselles-davignon"] },
    { y:"1908–12", t:"Roped together with Braque",
      text:"Picasso and Georges Braque work so closely they compare themselves to mountaineers on one rope. In analytical Cubism, Ma Jolie fractures figure and guitar into signs; in Still Life with Chair Caning, oilcloth and rope enter the picture. Representation becomes an argument assembled from evidence.",
      works:["ma-jolie","still-life-chair-caning"] },
    { y:"1917–25", t:"Classicism after the blast",
      text:"Designing Parade with the Ballets Russes brings travel, marriage and a sudden return to monumental figures drawn like ancient sculpture. Yet Cubism continues beside them. Three Musicians translates masked commedia players into interlocking colored planes — a paper collage enlarged into orchestral scale.",
      works:["three-musicians"] },
    { y:"1927–36", t:"Marie-Thérèse and the mirror",
      text:"The seventeen-year-old Marie-Thérèse Walter becomes his secret lover and the source of rounded, luminous bodies. Girl before a Mirror doubles her into daylight and shadow, surface and reflection. Domestic tenderness, erotic possession and formal invention occupy the same canvas without resolving one another.",
      works:["girl-before-a-mirror"] },
    { y:"1937", t:"Guernica",
      text:"News of the bombing of the Basque town reaches him in Paris while he is searching for a subject for Spain's exposition pavilion. Guernica converts newspaper horror into bull, horse, mother, lamp and scream. The Weeping Woman carries the catastrophe into one shattered face.",
      works:["guernica","the-weeping-woman"] },
    { y:"1945–73", t:"The old master refuses old age",
      text:"Ceramics, sculpture, political doves, lovers and furious revisions of Velázquez, Delacroix and Manet fill the final decades. His Las Meninas series makes fifty-eight variations in five months. Picasso dies at ninety-one with work in progress, leaving no stable late style — only appetite.",
      works:["las-meninas-picasso"] }
  ] },

"wassily-kandinsky": {
  why: "Kandinsky heard colors and painted the sound — then wrote abstraction's scripture to explain why a picture needs no object at all. His pre-war Compositions are apocalypses of pure color; his Bauhaus geometry is the same faith, cooled. Abstract art's loudest prophet, if not its first.",
  lookFor: ["Titles borrowed from music — improvisations, compositions","Storm chaos early, floating geometry late","Black calligraphic lines riding the color","No up, no down, no object"],
  goNext: [
    { t:"artist", id:"hilma-af-klint", why:"the secret first, years earlier" },
    { t:"artist", id:"paul-klee", why:"the Bauhaus neighbor and friend" },
    { t:"work", id:"composition-vii", why:"the apocalypse in four days" },
    { t:"movement", id:"abstract-art", why:"the faith he preached" }],
  coords: { F:80, D:55, E:80, C:25, M:20 },
  arc: [
    { y:"1866–96", t:"The lawyer who heard color",
      text:"A Moscow law-and-economics career, a professorship on offer at thirty — and two thunderbolts that end it: a Monet grainstack he fails to recognize as an object yet cannot stop feeling, and a Wagner opera during which, he wrote, he saw all his colors. He boards a train to Munich to start over as a student." },
    { y:"1901–08", t:"Munich, Murnau",
      text:"He founds an art school, teaches Gabriele Münter, and makes her his companion and sharpest ally. Summers in Murnau under the Alps crack objects open: Bavarian glass painting and Fauve color turn hillsides into chords. The Blue Mountain is barely a mountain anymore.",
      works:["blue-mountain"] },
    { y:"1910–11", t:"The spiritual turn",
      text:"He publishes On the Spiritual in Art — painting as inner necessity, color as vibration of the soul — and dates a wild untitled watercolor 1910, the self-declared first abstract picture (scholars argue for 1913; the ambition is not in dispute). His origin story: seeing one of his own canvases on its side at dusk, unrecognizable and more beautiful for it.",
      works:["first-abstract-watercolor"] },
    { y:"1911–14", t:"The Blue Rider",
      text:"With Franz Marc he founds Der Blaue Reiter — named, he joked, because Marc loved horses, he loved riders, and both loved blue. Improvisations, then the great Compositions: number VII, three metres of orchestrated apocalypse, painted in under a week after months of studies.",
      works:["improvisation-28","composition-vii"] },
    { y:"1914–21", t:"War and revolution",
      text:"The war expels him from Germany as an enemy alien; he leaves Münter and hundreds of works behind. In Moscow he marries Nina Andreevskaya and serves the revolution's art bureaus — until Soviet taste hardens against abstraction and the Bauhaus letter arrives like a rescue." },
    { y:"1922–33", t:"Bauhaus geometry",
      text:"A decade teaching at the Bauhaus turns the rider into an engineer: circle, triangle and line replace horse and cloud, codified in his treatise Point and Line to Plane. The circle, he now insists, is the greatest synthesis of oppositions — Composition VIII is its constitution.",
      works:["composition-viii","on-white-ii","yellow-red-blue","several-circles"] },
    { y:"1933–39", t:"Degenerate",
      text:"The Nazis close the Bauhaus and seize fifty-seven of his works from German museums; some hang in the Degenerate Art exhibition between mocking slogans. He moves to a small flat at Neuilly-sur-Seine outside Paris, takes French citizenship in 1939, and keeps painting." },
    { y:"1934–44", t:"The biomorphic coda",
      text:"In Paris the geometry softens: embryonic, microscopic creatures float on pastel grounds and, in Composition X, on black — forms that look grown rather than drawn. He paints through the occupation in the little apartment and dies there in December 1944, at seventy-eight.",
      works:["composition-x"] },
    { y:"1945–", t:"The inheritance",
      text:"Nina guards the estate; Gabriele Münter reveals she hid more than a hundred of his early works from the Nazis in her Murnau cellar and gives them to Munich in 1957. In New York, the museum Solomon Guggenheim built around his 'non-objective' paintings becomes simply the Guggenheim — a spiral temple for the faith Kandinsky preached." }
  ] },

"frida-kahlo": {
  why: "Kahlo painted her own reality — a body broken by a bus, a heart broken by Rivera — in the deadpan style of votive miracles. A third of her work is self-portrait, none of it self-pity. She turned autobiography into iconography, and the world is still wearing it.",
  lookFor: ["The unibrow, stated as fact","Retablo flatness and folk framing","The body opened like an anatomy plate","Monkeys, parrots and thorns as heraldry"],
  goNext: [
    { t:"artist", id:"diego-rivera", why:"the partner, twice" },
    { t:"artist", id:"leonora-carrington", why:"Mexico's other magic realist" },
    { t:"movement", id:"naive-art", why:"the votive tradition she weaponized" },
    { t:"movement", id:"surrealism", why:"the label she refused" }],
  coords: { F:-75, D:55, E:45, C:20, M:-60 },
  arc: [
    { y:"1907–25", t:"The body becomes fate",
      text:"Born in the Blue House in Coyoacán, Kahlo survives polio at six and plans to study medicine. At eighteen, a streetcar strikes the bus carrying her home; an iron handrail pierces her pelvis. Months immobilized in plaster turn a ceiling mirror and portable easel into a new life." },
    { y:"1926", t:"The first reflected self",
      text:"Painting from bed, she gives Self-Portrait in a Velvet Dress to Alejandro Gómez Arias, the boyfriend who survived the crash beside her. The long neck and aristocratic hand borrow Renaissance elegance, while the unbroken gaze establishes the compact she will keep: suffering may enter, but never as helplessness.",
      works:["self-portrait-velvet-dress"] },
    { y:"1928–31", t:"The elephant and the dove",
      text:"She joins Mexico City's communist and artistic circles, meets the muralist Diego Rivera, and marries him in 1929. Her parents nickname the pair the elephant and the dove. Following Rivera's commissions through San Francisco, Detroit and New York exposes her to industrial modernity and sharpened homesickness." },
    { y:"1932–33", t:"Detroit: the private disaster",
      text:"A traumatic miscarriage at Henry Ford Hospital becomes a small, unsparing self-portrait on a bloodied bed, six objects tethered to her body like medical constellations. My Birth makes creation equally brutal. While Rivera paints machines, Kahlo invents a language for bodily experience public murals could not contain.",
      works:["henry-ford-hospital","my-birth-kahlo"] },
    { y:"1934–39", t:"Marriage split in two",
      text:"Repeated operations, Rivera's affair with her sister Cristina, and Kahlo's own relationships with women and men pull the marriage apart. They divorce in 1939. The Two Fridas seats the loved Tehuana self beside the rejected European one, their exposed hearts connected by a single endangered artery.",
      works:["the-two-fridas"] },
    { y:"1938–40", t:"I paint my own reality",
      text:"André Breton welcomes her as a natural Surrealist and helps arrange shows in New York and Paris. Kahlo rejects the label: she does not paint dreams, she says, but her reality. Returning to Rivera and remarriage, she frames herself with thorns, a hummingbird, monkey and cat.",
      works:["thorn-necklace-hummingbird"] },
    { y:"1943–46", t:"The body opened",
      text:"Teaching at La Esmeralda, she brings devoted students to the Blue House when illness limits travel. The Broken Column replaces her spine with cracked architecture, straps her body together and covers the skin with nails. The tears are visible; the stare remains direct and almost administrative.",
      works:["the-broken-column"] },
    { y:"1946–53", t:"The wounded animal",
      text:"Spinal fusion in New York fails to end the pain; corsets, infections and morphine shape the following years. In The Wounded Deer her own face appears on an arrow-pierced stag still running through the forest. Diego and I compress jealousy into his third eye on her forehead.",
      works:["the-wounded-deer","diego-and-i"] },
    { y:"1953–54", t:"The bed enters the gallery",
      text:"Mexico finally gives her a solo exhibition. Against medical orders, she arrives by ambulance and receives guests from a four-poster bed installed in the gallery. After losing a leg, she paints politics as promised cure in Marxism Will Give Health to the Sick. She dies at forty-seven in the Blue House.",
      works:["marxism-health-sick"] }
  ] },

"salvador-dali": {
  why: "Dalí rendered dreams with a miniaturist's precision — soft watches, crutch-propped flesh, beaches of guilt — and marketed the unconscious better than anyone alive. Expelled from Surrealism for excess, he correctly replied that he was Surrealism. The mustache was load-bearing.",
  lookFor: ["Hard, glassy technique on impossible things","Double images hiding in plain sight","Vast empty beaches with long shadows","Soft things propped on crutches"],
  goNext: [
    { t:"artist", id:"giorgio-de-chirico", why:"the empty stage he inherited" },
    { t:"artist", id:"rene-magritte", why:"the dream, deadpan instead" },
    { t:"artist", id:"hieronymus-bosch", why:"the 500-year-old colleague" },
    { t:"movement", id:"surrealism", why:"the movement he claimed to be" }],
  coords: { F:-55, D:55, E:60, C:35, M:0 },
  arc: [
    { y:"1904–26", t:"The prodigy from Figueres",
      text:"Dalí grows up in Catalonia beneath the photograph and name of an older brother who died before his birth. At Madrid's Residencia de Estudiantes he befriends Lorca and Buñuel, cultivates theatrical eccentricity, and is expelled from the academy after declaring his examiners unfit to judge him." },
    { y:"1926–29", t:"Paris, Gala, rupture",
      text:"Picasso receives the young visitor in Paris; Dutch precision and Surrealist ideas soon meet in his glassy technique. In 1929 he makes Un Chien Andalou with Buñuel, joins Breton's circle, meets Gala Éluard, and paints The Great Masturbator. Gala becomes companion, manager and governing mythology.",
      works:["the-great-masturbator"] },
    { y:"1930–31", t:"The soft watches",
      text:"Dalí names his method paranoiac-critical: cultivate irrational associations, then render them with academic control. The Persistence of Memory shrinks the revelation to postcard size — clocks sagging over a Catalan shore, hard time turned edible. The image makes him internationally famous before he is thirty.",
      works:["the-persistence-of-memory"] },
    { y:"1934–36", t:"Surrealism cannot contain him",
      text:"His taste for publicity, money and political ambiguity exhausts André Breton's group, which stages a mock trial and moves to expel him. Dalí answers that the difference is simple: 'I am Surrealism.' Double images become his sharpest device, one form sliding into another before the eye can settle.",
      works:["swans-reflecting-elephants"] },
    { y:"1937", t:"Narcissus becomes a hand",
      text:"Metamorphosis of Narcissus pairs a kneeling body with a stone hand holding an egg, its exact visual echo. Dalí presents the painting and a poem to Freud in London, hoping for psychoanalytic recognition. Freud, previously skeptical of Surrealists, is struck by the Spaniard's technical mastery.",
      works:["metamorphosis-of-narcissus"] },
    { y:"1940–48", t:"America as theatre",
      text:"War sends Dalí and Gala to the United States, where shop windows, jewelry, fashion, film and celebrity make his self-invention a mass medium. Dream Caused by the Flight of a Bee suspends Gala above rock while tigers and a bayonet erupt from a pomegranate-sized chain of associations.",
      works:["dream-flight-bee"] },
    { y:"1949–55", t:"Nuclear mysticism",
      text:"Back in Catholic Spain, atomic physics and religious painting replace Freudian scandal as his declared frontier. Christ of Saint John of the Cross views the crucifixion from an impossible height; The Sacrament of the Last Supper builds devotion inside transparent geometry. Conversion and spectacle remain inseparable.",
      works:["christ-saint-john-cross","sacrament-last-supper"] },
    { y:"1960–74", t:"Building his own museum",
      text:"He transforms the burned municipal theatre of Figueres — where he first exhibited as a teenager — into the Dalí Theatre-Museum, designed as a walk inside his imagination. The Hallucinogenic Toreador condenses Venus, flies, bullfighter, blood and Gala into a vast catalogue of recurring obsessions.",
      works:["hallucinogenic-toreador"] },
    { y:"1982–89", t:"After Gala",
      text:"Gala's death leaves him isolated at Púbol Castle. A bedroom fire badly injures him, and questions surround his final years, signatures and caretakers. He dies in Figueres and is buried beneath the museum stage — the showman placed permanently at the center of his own theatre." }
  ] },

"jackson-pollock": {
  why: "Pollock laid the canvas on the floor, stepped inside it, and let the gesture itself become the picture — energy made visible, no brush touching cloth. The drip paintings made American art the world's center of gravity and turned the act of painting into the subject of painting.",
  lookFor: ["All-over webs with no center or edge","Skeins layered color over color","Flicks, pools and speed differences in the line","Scale that swallows your whole vision"],
  goNext: [
    { t:"artist", id:"lee-krasner", why:"partner, editor, keeper of the flame" },
    { t:"artist", id:"willem-de-kooning", why:"the rival who kept the figure" },
    { t:"technique", id:"dripping", why:"the method, patented in motion" },
    { t:"movement", id:"abstract-expressionism", why:"the arena" }],
  coords: { F:85, D:75, E:85, C:15, M:55 },
  arc: [
    { y:"1912–30", t:"West before East",
      text:"Born in Wyoming and moved repeatedly across Arizona and California, Pollock absorbs a western scale long before he paints one. Expelled from two schools, he follows his brother Charles to New York and studies with Thomas Hart Benton, whose muscular regionalist rhythms remain hidden beneath the later abstraction." },
    { y:"1930–42", t:"Murals, myths and survival",
      text:"Depression, alcoholism and uncertain work accompany years on the federal art project. Mexican muralists teach him that painting can surround a body; Picasso and Native American sand painting complicate the surface. Jungian analysis encourages masks, animals and buried symbols rather than tidy scenes." },
    { y:"1943", t:"The wall arrives first",
      text:"Peggy Guggenheim offers him a contract and commissions an enormous canvas for her townhouse. Mural is painted for a wall but behaves like weather crossing open land — a procession of repeated vertical forces. It establishes the scale and bodily rhythm the drip works will soon release.",
      works:["mural-pollock"] },
    { y:"1945–46", t:"The barn at Springs",
      text:"Pollock marries Lee Krasner, whose judgment, contacts and fierce editorial intelligence are fundamental to his career. They move to a modest house on Long Island. The unheated barn becomes his studio; taking canvas off the easel and onto its floor changes where painting can happen." },
    { y:"1947", t:"No brush between body and cloth",
      text:"Using sticks, hardened brushes and commercial enamel, he pours and flings paint while circling the horizontal canvas. Full Fathom Five buries nails, coins and a key in its web; Cathedral turns line into continuous architecture. The image records movement without becoming a diagram of it.",
      works:["full-fathom-five","cathedral-pollock"] },
    { y:"1948–49", t:"The breakthrough becomes a name",
      text:"Numbered titles resist the viewer's hunt for recognizable subjects. Number 5, 1948 and Number 1A layer skeins so densely that no single mark rules the field. Life magazine asks whether Pollock is the greatest living painter in the United States, converting difficulty into national celebrity.",
      works:["number-5-1948","number-1a-1948"] },
    { y:"1950", t:"Inside the painting",
      text:"Hans Namuth photographs and films Pollock at work, fixing the image of action painting in public memory. Autumn Rhythm stretches nearly five and a half metres; its black, white and earth-colored currents seem spontaneous but reveal pauses, revisions and sharply controlled changes of speed.",
      works:["autumn-rhythm"] },
    { y:"1951–52", t:"Black figures return",
      text:"Uneasy with the drip style becoming a signature, he pours mostly black enamel into calligraphic bodies, then returns to color at monumental scale. Convergence packs conflict into an all-over field; Blue Poles drives eight diagonal uprights through it, structure returning as an event rather than a frame.",
      works:["convergence-pollock","blue-poles"] },
    { y:"1953–56", t:"The silence after velocity",
      text:"Production slows, drinking returns, and his marriage fractures. On an August night in 1956, driving drunk near Springs, Pollock crashes and dies at forty-four; passenger Edith Metzger also dies. Krasner, away in Europe, returns to preserve the work and resist the myth swallowing the artist." }
  ] },

"mark-rothko": {
  why: "Rothko floated rectangles of color until they breathed — not abstractions, he insisted, but 'basic human emotions: tragedy, ecstasy, doom.' He wanted viewers eighteen inches away, engulfed. Stand there and the paintings do something no reproduction survives: they wait for you.",
  lookFor: ["Soft-edged rectangles hovering, never resting","Layered glazes glowing from underneath","Edges where two colors negotiate","Late works darkening toward the chapel"],
  goNext: [
    { t:"artist", id:"barnett-newman", why:"the zip beside the field" },
    { t:"artist", id:"caspar-david-friedrich", why:"the sublime, one century earlier" },
    { t:"artist", id:"jmw-turner", why:"light without objects, first draft" },
    { t:"movement", id:"color-field", why:"his quiet wing of AbEx" }],
  coords: { F:90, D:35, E:60, C:0, M:60 },
  arc: [
    { y:"1903–25", t:"From Dvinsk to New York",
      text:"Marcus Rothkowitz is born in Dvinsk in the Russian Empire to a Jewish family and emigrates to Portland, Oregon, at ten. A scholarship takes him to Yale, which he leaves without graduating. In New York, encountering a drawing class redirects an unsettled education toward painting." },
    { y:"1925–40", t:"Figures underground",
      text:"He paints portraits, interiors and compressed city scenes while teaching children for income. The subway pictures isolate elongated commuters beneath oppressive platforms and blank architecture. Even before abstraction, Rothko's real subject is the distance between people sharing an enclosed space." },
    { y:"1940–46", t:"Myth after history fails",
      text:"War and the persecution of European Jews make everyday subjects feel inadequate. He shortens his name to Mark Rothko and, with Adolph Gottlieb, turns toward Greek tragedy, myth and Surrealist biomorphism. Slow Swirl at the Edge of the Sea stages two delicate presences before an ancient, unstable horizon.",
      works:["slow-swirl-edge-sea"] },
    { y:"1947–49", t:"The multiforms open",
      text:"Recognizable bodies dissolve into irregular zones of floating color. Critics later call them multiforms, but Rothko treats them as a passage rather than a destination. The field grows taller, edges soften, and paint thins into veils: the conditions of his mature encounter quietly assemble." },
    { y:"1950–56", t:"Rectangles that breathe",
      text:"The classic format arrives — stacked fields, hovering boundaries, color built from many translucent layers. No. 61 (Rust and Blue), No. 14, and Orange and Yellow differ less by composition than emotional temperature. He asks that they hang low, close, and without decorative company.",
      works:["no-61-rust-blue","no-14-rothko","orange-and-yellow"] },
    { y:"1958", t:"The most expensive refusal",
      text:"A commission for the Four Seasons restaurant in Mies van der Rohe's Seagram Building promises unprecedented money. Rothko produces dark red and maroon panels, including Four Darks in Red, while imagining a sealed, oppressive room. Then he dines there, despises the luxury, and returns the fee.",
      works:["four-darks-in-red"] },
    { y:"1959–60", t:"The murals leave the restaurant",
      text:"The abandoned Seagram Murals become a dispersed family. Rothko donates a group to Tate, drawn partly by the prospect of hanging near Turner's late paintings. Their dim portals make color feel architectural — not windows outward, but thresholds the viewer cannot quite cross.",
      works:["seagram-murals"] },
    { y:"1964–67", t:"A chapel without doctrine",
      text:"John and Dominique de Menil commission a Houston sanctuary. Rothko shapes the room around fourteen nearly black paintings whose plum and violet surfaces emerge only through sustained looking. The Rothko Chapel opens in 1971 as an interfaith space, a year after he cannot see it completed.",
      works:["rothko-chapel-paintings"] },
    { y:"1968–70", t:"Black, gray, and the final morning",
      text:"After an aneurysm, doctors restrict his scale; separation, illness and depression darken the studio years. Untitled works divide black from gray with a hard horizon unlike the breathing earlier fields. Rothko dies by suicide in February 1970; the Seagram paintings reach Tate the same day.",
      works:["untitled-black-gray"] }
  ] },

"andy-warhol": {
  why: "Warhol pointed painting's eye at the supermarket and the front page — soup cans, Marilyns, car crashes — and silkscreened them until repetition itself became the message. 'I want to be a machine' was the century's slyest artistic confession. Image culture still runs on his operating system.",
  lookFor: ["Repetition until glamour becomes numbness","Silkscreen slippage and misregistration","Celebrity faces treated as icons","Factory flatness, zero brush ego"],
  goNext: [
    { t:"artist", id:"marcel-duchamp", why:"the question Warhol industrialized" },
    { t:"artist", id:"jean-michel-basquiat", why:"the late, electric friendship" },
    { t:"artist", id:"roy-lichtenstein", why:"the other half of Pop's rivalry" },
    { t:"technique", id:"silkscreen", why:"the assembly line" }],
  coords: { F:-30, D:15, E:70, C:75, M:10 },
  arc: [
    { y:"1928–49", t:"Pittsburgh to Manhattan",
      text:"Andrew Warhola grows up in a working-class Slovak immigrant family in Pittsburgh. Childhood illness keeps him home with movie magazines, drawing and radio. After studying commercial art, he moves to New York, drops the final letter of his surname, and begins illustrating fashion and advertising." },
    { y:"1949–60", t:"The successful invisible artist",
      text:"His blotted-line drawings and whimsical shoes make him one of Manhattan's most sought-after commercial illustrators. Window displays, record sleeves and magazine work teach him that style, repetition and distribution manufacture desire. Fine-art galleries remain less interested; Warhol studies their refusal carefully." },
    { y:"1961–62", t:"The supermarket enters painting",
      text:"Warhol paints comics and consumer goods, then presents thirty-two Campbell's Soup Cans — one for each flavor — like stock on a shelf. After Marilyn Monroe's death, Gold Marilyn and the Marilyn Diptych repeat her publicity image until glamour flickers into mourning. Silkscreen becomes his machine.",
      works:["campbells-soup-cans","gold-marilyn-monroe","marilyn-diptych"] },
    { y:"1962–63", t:"Death on the front page",
      text:"Car crashes, suicides, electric chairs and poisoned housewives enter the same repetitive system as soup and stars. 129 Die in Jet! enlarges tabloid catastrophe; Silver Car Crash repeats impact until shock becomes pattern. Mass media makes horror visible and, in the same gesture, numb.",
      works:["129-die-in-jet","silver-car-crash"] },
    { y:"1963–64", t:"The Factory",
      text:"A silver-painted studio fills with assistants, musicians, actors, drifters and cameras. Warhol delegates production and turns authorship into atmosphere. Brillo Boxes look indistinguishable from supermarket cartons except for their art-world setting, forcing the question Duchamp opened into the age of branding.",
      works:["brillo-box"] },
    { y:"1965–68", t:"Everybody gets a screen test",
      text:"He announces retirement from painting, manages the Velvet Underground and makes hundreds of films, from near-still portraits to marathon experiments. In June 1968 Valerie Solanas shoots him in the Factory. He survives after being declared clinically dead, scarred and physically fragile for life." },
    { y:"1970–79", t:"Society portraits and Mao",
      text:"A more controlled Factory turns commissioned portraits into a business, drawing criticism that the radical has become court painter to wealth. Warhol understands that compromise is part of the image economy. His Mao series treats communist authority with the same cosmetics, repetition and artificial color as celebrity.",
      works:["mao-warhol"] },
    { y:"1980–85", t:"The older star meets downtown",
      text:"Television, Interview magazine and relentless appearances make Warhol himself a circulating image. Collaborations with the younger Jean-Michel Basquiat mix logos, headlines and gestural painting; critics often patronize the partnership, but it becomes a difficult conversation about fame, race, commerce and authorship." },
    { y:"1986–87", t:"The mask looks back",
      text:"Late self-portraits isolate the fright wig above camouflage-like color, the face spectral and already posthumous. Warhol dies unexpectedly after gallbladder surgery in February 1987. His estate becomes the foundation that later creates Pittsburgh's Warhol Museum — repetition preserved as an archive of American looking.",
      works:["self-portrait-fright-wig"] }
  ] },

"sandro-botticelli": {
  why: "Botticelli painted the Renaissance's most famous faces without its favorite tricks — no deep perspective, no heavy anatomy, just line so graceful it survived three centuries of neglect. His pagan goddesses, painted with a Madonna-painter's devotion, gave Europe permission to adore beauty for its own sake again.",
  lookFor: ["Line doing all the work — contour over volume","Melancholy in every face, even the joyful ones","Weightless figures that barely touch the ground","Gold used like a whisper, not a shout"],
  goNext: [
    { t:"work", id:"primavera", why:"the puzzle-picture of the age" },
    { t:"artist", id:"leonardo-da-vinci", why:"the rival manner that eclipsed his" },
    { t:"movement", id:"early-renaissance", why:"the workshop world he crowned" }],
  coords: { F:-70, D:-15, E:15, C:-20, M:15 },
  arc: [
    { y:"c. 1445–64", t:"The tanner's son",
      text:"Born in Florence's Ognissanti quarter, youngest son of a tanner, carrying a nickname inherited from a stocky brother — botticello, 'little barrel.' After a spell with a goldsmith he enters Filippo Lippi's workshop, learning the master's linear grace and, presumably, discretion: Lippi was the friar who had eloped with a nun." },
    { y:"1470–75", t:"The Medici orbit",
      text:"His own workshop opens, and the city's ruling family adopts it. The Adoration of the Magi stacks three generations of Medici around the manger — and, at the right edge, a young painter in ochre stares straight out at you: Botticelli, signing with his face.",
      works:["adoration-magi-botticelli"] },
    { y:"c. 1476–80", t:"Simonetta",
      text:"Simonetta Vespucci, the adored beauty of Florence, dies at twenty-two; the city mourns theatrically. Her features — reportedly, endlessly — keep surfacing in his women for the rest of his career, most openly in the jeweled nymph-portrait now in Frankfurt.",
      works:["idealized-portrait-of-a-lady"] },
    { y:"c. 1480–85", t:"Mythology at altar scale",
      text:"For a Medici villa he paints what nobody had painted for a thousand years: pagan goddesses at the size and seriousness of altarpieces. Primavera fills an orange grove with philosophy; the Birth of Venus floats a nude goddess ashore; Venus watches Mars sleep off love like a spent soldier.",
      works:["primavera","the-birth-of-venus","venus-and-mars"] },
    { y:"1481–82", t:"Rome interlude",
      text:"Sixtus IV summons Florence's best to fresco the walls of his new chapel — the Sistine. Botticelli paints Moses and the temptations of Christ alongside Perugino, then goes home. Thirty years later a sculptor will paint the ceiling and swallow the room whole." },
    { y:"1480s", t:"The Madonna industry",
      text:"Between the myths, the workshop hums with devotion: tondi — round paintings — of the Virgin among angels, the Magnificat with its crown of gold script. Half of Florence's fashionable piety passes across his easel.",
      works:["madonna-of-the-magnificat"] },
    { y:"1490s", t:"Savonarola's fire",
      text:"The friar Savonarola seizes Florence's conscience; vanities burn in the piazza. Vasari says Botticelli burned his own profane pictures — historians argue, the style change doesn't: the line hardens, the serenity curdles. The Calumny of Apelles pleads for the falsely accused in a suddenly paranoid city.",
      works:["calumny-of-apelles"] },
    { y:"1500", t:"The Mystical Nativity",
      text:"His only signed and dated painting, inscribed in Greek with an apocalyptic countdown 'in the half time after the time.' Angels embrace mortals on a golden roof while small devils scurry into cracks in the earth. Joy and end-times dread, on one panel.",
      works:["the-mystical-nativity"] },
    { y:"1510–", t:"Eclipse and resurrection",
      text:"He dies poor and unfashionable, out-modernized by Leonardo's smoke and Michelangelo's muscle, and stays obscure for three hundred and fifty years — until Ruskin and the Pre-Raphaelites resurrect him as a saint of line. Today his Venus may be the most reproduced painted face on earth." }
  ] },

"albrecht-durer": {
  why: "Dürer made the print an art form and himself the first international art brand — the AD monogram was famous from Lisbon to Kraków while he was still in his twenties. He painted himself like Christ, drew weeds and hares like scripture, and put German art permanently on the map.",
  lookFor: ["The AD monogram, placed like a maker's seal","Engraved lines packed until they read as tone","Nature studied with devotional patience","Self-portraits that stare back as equals"],
  goNext: [
    { t:"work", id:"melencolia-i", why:"the thinking person's engraving" },
    { t:"artist", id:"hieronymus-bosch", why:"the other Northern imagination" },
    { t:"movement", id:"northern-renaissance", why:"the world he anchored" }],
  coords: { F:-80, D:15, E:35, C:35, M:-40 },
  arc: [
    { y:"1471–90", t:"The goldsmith's son",
      text:"Third of a Nuremberg goldsmith's eighteen children, apprenticed first to his father, then to the painter Wolgemut. At thirteen he draws himself in silverpoint from a mirror — the earliest surviving self-portrait drawing by any major artist — and notes in the corner, matter-of-factly, that he did." },
    { y:"1494–95", t:"Over the Alps",
      text:"The first Italian journey: Venice for Bellini and Mantegna, and on the road home something quieter and stranger — watercolor views of Alpine valleys made for no client at all, arguably Europe's first pure landscapes." },
    { y:"1498", t:"The Apocalypse",
      text:"At twenty-six he publishes his own illustrated Revelation — fifteen woodcuts, printed and sold under his own name, the Four Horsemen at full gallop. It makes him famous across Europe at print-shop prices: the first artist whose reputation traveled faster than his paintings.",
      works:["four-horsemen"] },
    { y:"1500", t:"The Christ-pose",
      text:"The Munich self-portrait: frontal, symmetrical, fur-collared, the pose a millennium of art reserved for Christ. Blasphemy or thesis — Dürer meant the thesis: the artist creates, as the Creator does. Nobody had claimed rank like this in paint before.",
      works:["self-portrait-at-28"] },
    { y:"1502–03", t:"The reverence of small things",
      text:"A wild hare, a square foot of weeds. He paints them with the patience other men saved for saints, every whisker and seed-head accounted for — and signs them, because studies this good are not studies anymore.",
      works:["young-hare","great-piece-of-turf"] },
    { y:"1504–07", t:"Measuring beauty",
      text:"Adam and Eve constructed by compass and ratio — ideal proportion, demonstrated in an engraving. Then Venice again, richer and pricklier: 'Here I am a gentleman, at home a parasite.' When an Italian engraver forges his monogram, Dürer goes to law — art's first trademark dispute, more or less.",
      works:["adam-and-eve-durer"] },
    { y:"1513–14", t:"The master engravings",
      text:"In two years he cuts the three plates that exhaust the medium: the Knight riding grimly past Death and the Devil, Saint Jerome sunlit in his study, and Melencolia I — genius stalled among its own instruments. Four centuries of interpretation have not emptied them.",
      works:["knight-death-and-the-devil","melencolia-i"] },
    { y:"1515–21", t:"The rhinoceros and the world",
      text:"He draws a rhinoceros he never saw from a written description — armor-plated, wrong, unforgettable; schoolbooks used it for three centuries. In the Netherlands he is feted like a prince, marvels at Aztec treasure ('the subtle ingenia of men in foreign lands'), and catches the marsh fever that will shorten his life.",
      works:["durers-rhinoceros","praying-hands"] },
    { y:"1526–28", t:"Emigravit",
      text:"The last years go to theory — books on measurement, proportion, fortification — the artist as scientist, in print like everything he did. He dies at fifty-six; Nuremberg buries him under a single word chosen by his humanist friends: Emigravit. He has moved on." }
  ] },

"pieter-bruegel": {
  why: "Bruegel invented the view from everywhere: whole valleys, whole villages, whole seasons on one panel, with humanity seen from just high enough to love and laugh at simultaneously. Skip his peasants at your peril — the wedding feasts and snowbound hunters carry more philosophy than most allegories.",
  lookFor: ["The high viewpoint — you hover, godlike but fond","Dozens of small dramas per panel; no single hero","Proverbs and follies hidden in plain sight","Seasons carrying the emotional weather"],
  goNext: [
    { t:"work", id:"hunters-in-the-snow", why:"winter itself, on loan to Vienna" },
    { t:"artist", id:"hieronymus-bosch", why:"the ancestor he modernized" },
    { t:"movement", id:"northern-renaissance", why:"his branch of the family tree" }],
  coords: { F:-80, D:5, E:20, C:25, M:20 },
  arc: [
    { y:"c. 1525–51", t:"Murky beginnings",
      text:"Birthplace disputed, birth year guessed — Bruegel enters history in 1551, registered as a master painter in Antwerp, Europe's richest port. He trained, tradition says, with Pieter Coecke van Aelst, whose daughter he would one day marry — after being, by one account, a boarder in the house as a boy." },
    { y:"1552–54", t:"The Alps swallow him",
      text:"He travels to Italy like every ambitious northerner — and comes back carrying mountains instead of Madonnas. Rome barely shows in his art; the crossing does, forever. Van Mander said he 'swallowed the mountains and spat them out as panels.'" },
    { y:"1555–59", t:"The new Bosch",
      text:"For the print publisher Hieronymus Cock he designs devilries and sins in Bosch's manner — bestsellers signed, at first, with a name spelled Brueghel. In 1559 he drops the 'h' and, gradually, the borrowed imagination." },
    { y:"1559–60", t:"Encyclopedias of us",
      text:"Two panels catalogue humanity like a naturalist's plates: over a hundred proverbs acted out in one impossible village, then some ninety children's games in another. Folly, mapped from above, with terrifying good humor.",
      works:["netherlandish-proverbs","childrens-games"] },
    { y:"c. 1560–62", t:"Death marches",
      text:"The Triumph of Death sends skeleton armies across a burning world — Bosch's hell secularized into war reportage. And somewhere in these years, a ploughman keeps ploughing while Icarus drowns in the corner: the painting Auden turned into modern poetry's favorite lesson about suffering.",
      works:["triumph-of-death","fall-of-icarus"] },
    { y:"1563", t:"Brussels, Babel",
      text:"He marries Mayken Coecke and moves to Brussels, the court city. The Tower of Babel rises under his brush — Colosseum arches, Flemish cranes, doom in the masonry — painted with such engineering love that architects still argue over its construction schedule.",
      works:["the-tower-of-babel"] },
    { y:"1565", t:"The months",
      text:"For the banker Jonghelinck's dining room he paints the cycle of the seasons — the calendar tradition of medieval prayer books blown up to panel scale. Hunters in the Snow becomes the West's definitive winter; The Harvesters, its sweating gold summer.",
      works:["hunters-in-the-snow","the-harvesters"] },
    { y:"1567–68", t:"Peasants, close up",
      text:"The viewpoint descends: wedding feasts and dances at table height, painted — van Mander swears — after crashing village weddings in disguise. And the Blind Leading the Blind stumbles diagonally toward the ditch while Spanish terror grips the Netherlands; readers of politics into it have never lacked material.",
      works:["the-peasant-wedding","blind-leading-the-blind"] },
    { y:"1569", t:"Burn the drawings",
      text:"He dies around forty-four, instructing his wife to burn a set of drawings 'too biting' to survive him — self-censorship in the Duke of Alba's police state, most historians think. Two painter sons carry the franchise; four centuries later, the man who painted us from above still has no equal at it." }
  ] },

"el-greco": {
  why: "A Greek icon painter who detoured through Venice and Rome, was shrugged off by a king, and spent forty years in Toledo stretching bodies toward heaven. Dismissed for centuries as mad, El Greco turned out to be early: Picasso built the Demoiselles on his bones, and the Expressionists claimed him as founder.",
  lookFor: ["Figures stretched like candle flames","Storm-light with no visible sun","Cloud and flesh made of the same substance","Greek signature on a Spanish wall"],
  goNext: [
    { t:"work", id:"view-of-toledo", why:"Spain's first, strangest landscape" },
    { t:"artist", id:"diego-velazquez", why:"the next Spanish eye" },
    { t:"artist", id:"pablo-picasso", why:"who raided the Fifth Seal" },
    { t:"movement", id:"mannerism", why:"the style he took past its limits" }],
  coords: { F:-65, D:70, E:70, C:10, M:40 },
  arc: [
    { y:"1541–66", t:"Icon painter of Candia",
      text:"Domenikos Theotokopoulos, born on Venetian Crete, trains in the post-Byzantine icon workshops and is a certified master by his early twenties. The gold-ground grammar of icons — flatness, elongation, light from nowhere — never leaves him. Neither does the Greek signature he will put on everything, to the end." },
    { y:"1567–76", t:"Venice, then Rome",
      text:"In Venice he studies Titian's color and Tintoretto's fire; in Rome, by the famous report, he offers to repaint Michelangelo's Last Judgment 'with decency' if they tear it down. Roman doors close politely. A Cretan with opinions needs a city of his own." },
    { y:"1577–79", t:"Toledo",
      text:"He arrives in Spain's old capital for a cathedral commission and never leaves. The Disrobing of Christ blazes crimson at the center of a mob — and ends in a lawsuit over price, the first of many. He litigated all his life, usually correctly.",
      works:["disrobing-of-christ"] },
    { y:"1580–84", t:"The king shrugs",
      text:"Philip II tries him for the Escorial and rejects the result. The court door shuts — and shuts him into Toledo, its priests, scholars and lawyers, the luckiest rejection in Spanish art. Madrid got the factory painters; Toledo got the visionary." },
    { y:"1586–88", t:"The Burial",
      text:"For his own parish he paints the town miracle: saints descending to bury a pious count while Toledo's establishment watches in ruff-collared rows and heaven boils overhead. It has never moved from the wall it was made for, and Toledo has never stopped charging admission.",
      works:["burial-of-the-count-of-orgaz"] },
    { y:"1590s", t:"Portraits of souls",
      text:"Between altarpieces he paints the city's men in austere black and white — the Nobleman with his Hand on his Chest above all, a gesture somewhere between oath and confession. Velázquez studied these; Spanish portraiture's gravity starts here.",
      works:["nobleman-hand-on-chest"] },
    { y:"c. 1599", t:"The city as storm",
      text:"View of Toledo: the first great landscape of Spanish art, with the skyline rearranged and the weather apocalyptic. Not a portrait of a place — a portrait of a place's soul, three centuries before anyone would call that Expressionism.",
      works:["view-of-toledo"] },
    { y:"1600–14", t:"The long dissolve",
      text:"The late style stretches figures like flames and lights them from inside: Laocoön writhing before a Toledo backdrop, the Fifth Seal's bodies whipping upward, shepherds adoring by phosphorescence. Contemporaries mutter about madness; he keeps signing in Greek.",
      works:["laocoon-el-greco","the-opening-of-the-fifth-seal","adoration-shepherds-el-greco"] },
    { y:"1614–", t:"Vindicated by moderns",
      text:"He dies in 1614 and spends the next 250 years as 'the mad Greek' — the astigmatism theory of his elongations dies particularly hard. Then Manet visits, Cézanne takes notes, and a young Picasso studies the Fifth Seal in a friend's apartment while sketching the Demoiselles. The last old master turns out to be the first modern." }
  ] },

"edouard-manet": {
  why: "Manet is the hinge: the last old master and the first modern painter on one easel. He took Titian and Velázquez, stripped the varnish of myth, and painted his own Paris looking back at the viewer — scandalizing the Salon so thoroughly that modern art's origin story is usually dated to his Olympia.",
  lookFor: ["Flat, frontal light that kills academic shadow","Blacks used as a full color, learned from Spain","Modern Parisians where gods used to stand","A gaze that meets yours and doesn't flinch"],
  goNext: [
    { t:"work", id:"olympia", why:"where modern painting picks a fight" },
    { t:"artist", id:"claude-monet", why:"the movement he armed but never joined" },
    { t:"artist", id:"diego-velazquez", why:"'the painter of painters,' his words" },
    { t:"movement", id:"impressionism", why:"the revolution next door" }],
  coords: { F:-80, D:15, E:65, C:35, M:-15 },
  arc: [
    { y:"1832–49", t:"The judge's son",
      text:"Born into the Parisian legal bourgeoisie and expected to join it. He fails the naval academy entrance twice — sailing to Rio as a cadet in between — and comes home certain of exactly one thing. The family compromises on art school, the way such families do." },
    { y:"1850–58", t:"Couture's difficult pupil",
      text:"Six years in Thomas Couture's studio, quarreling with the master's theatrical history-machine. His real education happens in the Louvre, copying Velázquez and Goya — Spain enters his bloodstream a decade before he sets foot there." },
    { y:"1862", t:"Modern life, painted flat",
      text:"Music in the Tuileries crowds his own set — Baudelaire, Gautier, himself — into a fashionable park and paints them with scandalous flatness. Baudelaire had called for a 'painter of modern life'; Manet quietly files his application.",
      works:["music-in-the-tuileries"] },
    { y:"1863", t:"The Refusés",
      text:"The Salon rejects Déjeuner sur l'herbe; the emperor opens a Salon of Rejects and it becomes the scandal of the age — a naked woman lunching with two dressed dandies, painted raw, quoting Raphael the whole time. The young painters take it as a flag.",
      works:["le-dejeuner-sur-lherbe"] },
    { y:"1865", t:"Olympia",
      text:"The scandal to end them all: Titian's Venus recast as a working Parisienne who meets your eye. Guards protect the canvas from umbrellas; critics reach for zoology. Manet flees to Spain and finds Velázquez — 'the painter of painters' — which only sharpens the knife.",
      works:["olympia","the-fifer"] },
    { y:"1868–74", t:"The Guerbois gang",
      text:"At the Café Guerbois the future Impressionists orbit him; Berthe Morisot enters the circle as colleague and muse — he paints her a dozen times; she marries his brother. He answers Goya with the Execution of Maximilian (banned from showing) and paints modernity as steam behind a garden fence.",
      works:["the-balcony-manet","berthe-morisot-violets","execution-of-maximilian","the-railway"] },
    { y:"1874–80", t:"Almost Impressionist",
      text:"Summers at Argenteuil beside Monet lighten his palette to river-glare — yet he refuses, every time, to hang with the Impressionists. The Salon or nothing: revolution, he insists, is won inside the institution. Both sides claim him anyway." },
    { y:"1880–82", t:"Painting against the clock",
      text:"Locomotor ataxia — syphilis's long arithmetic — closes in. He paints small things greatly: flowers, a lemon, a single asparagus spear sent to a collector who had overpaid for a bundle ('there was one missing'). Then, seated and dying, the Bar at the Folies-Bergère and its impossible mirror.",
      works:["asparagus-manet","a-bar-at-the-folies-bergere"] },
    { y:"1883–90", t:"The subscription",
      text:"A gangrenous leg is amputated; he dies eleven days later, at fifty-one, weeks after the Legion of Honour finally arrived. In 1890 Monet organizes a public subscription that forces Olympia into the national collection — the scandal, nationalized, seven years too late for its painter." }
  ] },

"raphael": {
  why: "For three centuries 'painting well' simply meant painting like Raphael. The prodigy from Urbino absorbed Leonardo's smoke and Michelangelo's muscle, added a grace neither possessed, and died at thirty-seven having defined harmony itself — so completely that rebels from the Pre-Raphaelites onward had to name themselves against him.",
  lookFor: ["Compositions that resolve like chords","Faces sweet without sugar — the hardest trick","Perspective staged like theatre architecture","Grace that hides the enormous machinery"],
  goNext: [
    { t:"work", id:"the-school-of-athens", why:"humanism's group portrait" },
    { t:"artist", id:"leonardo-da-vinci", why:"the smoke he studied" },
    { t:"artist", id:"michelangelo", why:"the rival on the ceiling next door" },
    { t:"movement", id:"high-renaissance", why:"the summit he shares" }],
  coords: { F:-85, D:-20, E:-30, C:0, M:45 },
  arc: [
    { y:"1483–94", t:"Urbino's child",
      text:"Born in Urbino, Italy's most civilized small court, son of the duke's painter — who dies when Raphael is eleven, leaving the boy a workshop and a head start in courtesy that would matter as much as talent. He is, by all accounts, impossible to dislike. It becomes a career strategy." },
    { y:"c. 1500–04", t:"Perugino's best student",
      text:"He absorbs Perugino's sweetness so completely that attribution still starts fights — then surpasses it politely. The Marriage of the Virgin out-builds his teacher's version of the same scene: a temple in perfect perspective, a piazza breathing, the future arranged in advance.",
      works:["marriage-of-the-virgin"] },
    { y:"1504–08", t:"Florence: the sponge",
      text:"Four years studying the two volcanoes — Leonardo's sfumato and psychology, Michelangelo's anatomy — without inheriting either temperament. The Madonnas of these years, the Meadow among them, make grace look reproducible. It wasn't; it just looked that way in his hands.",
      works:["madonna-of-the-meadow","raphael-self-portrait"] },
    { y:"1508–11", t:"The Stanze",
      text:"Julius II hands a twenty-five-year-old the papal apartments while Michelangelo paints the chapel ceiling down the corridor. The School of Athens answers: philosophy staged as architecture, antiquity cast with modern faces, and Michelangelo added late — brooding on the steps — after Raphael saw the ceiling.",
      works:["the-school-of-athens"] },
    { y:"1512–14", t:"Madonnas and a sea-nymph",
      text:"The Sistine Madonna walks out of heaven's curtains for a provincial altar, trailing the two most merchandised putti in history. Across town, for the banker Chigi's garden villa, Galatea rides a shell through pure pagan joy — sacred and profane, both effortless, both his.",
      works:["sistine-madonna","triumph-of-galatea"] },
    { y:"1514–17", t:"The first art director",
      text:"He succeeds Bramante as architect of St Peter's, superintends Rome's antiquities — his letter to Leo X pleading for the ruins is conservation's founding document — and runs a fifty-hand workshop on his drawings. Half of what 'Raphael' means was produced by the system he invented." },
    { y:"c. 1514–19", t:"Castiglione and La Fornarina",
      text:"Two loves, two portraits: his friend Castiglione, author of the courtier's handbook, painted in greys that Rembrandt would later copy at auction; and the baker's daughter Margherita, wearing his name on her armband — and, found under the repaint centuries later, a ruby wedding ring.",
      works:["baldassare-castiglione","la-fornarina"] },
    { y:"1518–20", t:"Transfiguration",
      text:"His last altarpiece splits the world in two: Christ blazing above, the possessed boy untreatable below — heaven's certainty stacked on human failure. It was still in his studio when he died, and Rome carried it behind his coffin.",
      works:["the-transfiguration-raphael"] },
    { y:"1520–", t:"Good Friday, aged thirty-seven",
      text:"A short fever — Vasari blames a night of excess and the doctors' bleeding — kills him on Good Friday, reportedly his thirty-seventh birthday exactly. Rome mourns like a state; he is buried in the Pantheon at his own request. For the next three centuries, academies teach him as the answer key." }
  ] }
};
